assign psum_2_GLB_out_ready 				= router_cluster_psum_data_out_sel & GLBCluster_psum_SRAM_Bank_2_data_in_ready;
assign psum_0_south_out_ready 				= router_psum_0_south_out_ready; 
assign psum_1_south_out_ready 				= router_psum_1_south_out_ready; 
assign psum_2_south_out_ready 				= router_psum_2_south_out_ready; 
			
assign psum_0_PE_in_valid 					= PECluster_psum_0_out_valid; 
assign psum_1_PE_in_valid 					= PECluster_psum_1_out_valid; 
assign psum_2_PE_in_valid 					= PECluster_psum_2_out_valid; 
assign psum_0_GLB_in_valid 					= GLBCluster_psum_SRAM_Bank_0_data_out_valid & cg_ctrl_psum_add; 	
assign psum_1_GLB_in_valid 					= GLBCluster_psum_SRAM_Bank_1_data_out_valid & cg_ctrl_psum_add; 
assign psum_2_GLB_in_valid 					= GLBCluster_psum_SRAM_Bank_2_data_out_valid & cg_ctrl_psum_add; 
assign psum_0_north_in_valid 				= router_psum_0_north_in_valid; 
assign psum_1_north_in_valid 				= router_psum_1_north_in_valid; 
assign psum_2_north_in_valid 				= router_psum_2_north_in_valid;
			
assign psum_0_PE_in_bits 					= PECluster_psum_0_out; 
assign psum_1_PE_in_bits 					= PECluster_psum_1_out; 
assign psum_2_PE_in_bits 					= PECluster_psum_2_out; 
assign psum_0_GLB_in_bits 					= GLBCluster_psum_SRAM_Bank_0_data_out; 
assign psum_1_GLB_in_bits 					= GLBCluster_psum_SRAM_Bank_1_data_out;
assign psum_2_GLB_in_bits 					= GLBCluster_psum_SRAM_Bank_2_data_out; 
assign psum_0_north_in_bits 				= router_psum_0_north_in;	
assign psum_1_north_in_bits 				= router_psum_1_north_in; 	
assign psum_2_north_in_bits 				= router_psum_2_north_in; 

// cluster group control
assign cg_ctrl_clock = clock;
assign cg_ctrl_reset = reset;
assign cg_ctrl_GLB_psum_0_write_done 		= GLBCluster_psum_SRAM_Bank_0_write_done; 
assign cg_ctrl_GLB_psum_1_write_done 		= GLBCluster_psum_SRAM_Bank_1_write_done; 
assign cg_ctrl_GLB_psum_2_write_done 		= GLBCluster_psum_SRAM_Bank_2_write_done; 
		
assign cg_ctrl_GLB_iact_0_0_write_done 		= GLBCluster_iact_SRAM_Bank_0_0_write_done;	
assign cg_ctrl_GLB_iact_0_1_write_done 		= GLBCluster_iact_SRAM_Bank_0_1_write_done; 		
assign cg_ctrl_GLB_iact_0_2_write_done 		= GLBCluster_iact_SRAM_Bank_0_2_write_done; 
assign cg_ctrl_GLB_iact_1_0_write_done 		= GLBCluster_iact_SRAM_Bank_1_0_write_done;	
assign cg_ctrl_GLB_iact_1_1_write_done 		= GLBCluster_iact_SRAM_Bank_1_1_write_done; 		
assign cg_ctrl_GLB_iact_1_2_write_done 		= GLBCluster_iact_SRAM_Bank_1_2_write_done; 
assign cg_ctrl_GLB_iact_2_0_write_done 		= GLBCluster_iact_SRAM_Bank_2_0_write_done;	
assign cg_ctrl_GLB_iact_2_1_write_done 		= GLBCluster_iact_SRAM_Bank_2_1_write_done; 		
assign cg_ctrl_GLB_iact_2_2_write_done 		= GLBCluster_iact_SRAM_Bank_2_2_write_done; 
		
assign cg_ctrl_GLB_iact_0_0_read_done  		= GLBCluster_iact_SRAM_Bank_0_0_read_done; 		
assign cg_ctrl_GLB_iact_0_1_read_done  		= GLBCluster_iact_SRAM_Bank_0_1_read_done; 		
assign cg_ctrl_GLB_iact_0_2_read_done  		= GLBCluster_iact_SRAM_Bank_0_2_read_done; 	
assign cg_ctrl_GLB_iact_1_0_read_done  		= GLBCluster_iact_SRAM_Bank_1_0_read_done; 		
assign cg_ctrl_GLB_iact_1_1_read_done  		= GLBCluster_iact_SRAM_Bank_1_1_read_done; 		
assign cg_ctrl_GLB_iact_1_2_read_done  		= GLBCluster_iact_SRAM_Bank_1_2_read_done; 
assign cg_ctrl_GLB_iact_2_0_read_done  		= GLBCluster_iact_SRAM_Bank_2_0_read_done; 		
assign cg_ctrl_GLB_iact_2_1_read_done  		= GLBCluster_iact_SRAM_Bank_2_1_read_done; 		
assign cg_ctrl_GLB_iact_2_2_read_done  		= GLBCluster_iact_SRAM_Bank_2_2_read_done; 

assign cg_ctrl_read_psum_en 				= read_psum_en; 
assign cg_ctrl_cg_en 						= cg_en; 
assign cg_ctrl_PE_all_write_fin 			= PECluster_all_write_fin;
assign cg_ctrl_src_GLB_load_fin 			= src_GLB_load_fin;
assign cg_ctrl_psum_acc_en					= psum_acc_en;
assign cg_ctrl_psum_acc_fin					= psum_acc_fin;


// ====================================================================	//
// 						 		Sequential  							//
// ====================================================================	//
always@(posedge clock) begin
	if(reset) begin
		all_cal_fin_reg <= 1'b0;
	end
	else if(idle_wire) begin
		all_cal_fin_reg <= 1'b0;
	end
	else begin
		all_cal_fin_reg <= all_cal_fin_reg | PECluster_all_cal_fin;
	end
end
  
  
endmodule

// ===== repo/FPGA_design/src/CSC_encoder/CSC_encoderr.v =====
// ====================================================================================================== //
// This module is CSC_Encoder.
// CSC_Encoder read data in column direction.
//
// The input matrix_height and matrix_width is output matrix shape.
// An additive signal clear_iact_SRAM is used to clear GBL SRAM Bank.
// The clear represents write contineous zero to clear SRAM Bank module.
// data in SRAM will not be clear, but SRAM Bank module will clear writing address.
//
// PEs don't support over 2 contineous zero column, therefore, this module can detect 2 contineous column,
// and set the second column contains one value 1 and coressponding count will be set the maximum value to
// let PES detect this column has been modify, and PE will dischard this valud.
// 
// ====================================================================================================== //


module CSC_Encoder #(
	parameter ADDR_WIDTH 	= 7,
	parameter COUNT_WIDTH 	= 4,
	parameter DATA_WIDTH 	= 8
	)
(
	input         							clock,
	input         							reset,
	output        							data_in_ready,
	input         							data_in_valid,
	input 	signed 	[7:0]  					data_in,
					
	input         							address_out_ready,
	output        							address_out_valid,
	output [ADDR_WIDTH-1:0] 				address_out,
	input         							data_out_ready,
	output        							data_out_valid,
	output [DATA_WIDTH+COUNT_WIDTH-1:0] 	data_out,
					
	input  [4:0]  							matrix_height,
	input  [4:0]  							matrix_width,
	
	input									clear_iact_SRAM,
	
	output									one_vector_done
);


// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
localparam DATA_IN_BITWIDTH  = 8;


// ====================================================================	//
// 						 		Instantiation  							//
// ====================================================================	//
wire  								data_in_FIFO_clock; 
wire  								data_in_FIFO_reset; 
wire  								data_in_FIFO_data_in_ready; 
wire  								data_in_FIFO_data_in_valid; 
wire signed	[7:0] 					data_in_FIFO_data_in; 
wire  								data_in_FIFO_data_out_ready; 
wire  								data_in_FIFO_data_out_valid; 
wire signed	[7:0] 					data_in_FIFO_data_out; 
						
wire  								address_out_FIFO_clock; 
wire  								address_out_FIFO_reset; 
wire  								address_out_FIFO_data_in_ready; 
wire  								address_out_FIFO_data_in_valid; 
wire [ADDR_WIDTH-1:0] 				address_out_FIFO_data_in; 
wire  								address_out_FIFO_data_out_ready;
wire  								address_out_FIFO_data_out_valid; 
wire [ADDR_WIDTH-1:0] 				address_out_FIFO_data_out; 

wire  								data_out_FIFO_clock; 
wire  								data_out_FIFO_reset;
wire  								data_out_FIFO_data_in_ready; 
wire  								data_out_FIFO_data_in_valid; 
wire [DATA_WIDTH+COUNT_WIDTH-1:0] 	data_out_FIFO_data_in; 
wire  								data_out_FIFO_data_out_ready; 
wire  								data_out_FIFO_data_out_valid; 
wire [DATA_WIDTH+COUNT_WIDTH-1:0] 	data_out_FIFO_data_out; 


CSC_switch_FIFO  #(
	.DATA_WIDTH(DATA_IN_BITWIDTH)
	)
Data_in_FIFO( 
	.clock			(data_in_FIFO_clock			),
	.reset			(data_in_FIFO_reset			),
	.data_in_ready	(data_in_FIFO_data_in_ready	),
	.data_in_valid	(data_in_FIFO_data_in_valid	),
	.data_in 		(data_in_FIFO_data_in		),
	.data_out_ready	(data_in_FIFO_data_out_ready),
	.data_out_valid	(data_in_FIFO_data_out_valid),
	.data_out 		(data_in_FIFO_data_out		)
);

CSC_switch_FIFO  #(
	.DATA_WIDTH(ADDR_WIDTH)
	)
Address_out_FIFO( 
	.clock			(address_out_FIFO_clock			),
	.reset			(address_out_FIFO_reset			),
	.data_in_ready	(address_out_FIFO_data_in_ready	),
	.data_in_valid	(address_out_FIFO_data_in_valid	),
	.data_in 		(address_out_FIFO_data_in		),
	.data_out_ready	(address_out_FIFO_data_out_ready),
	.data_out_valid	(address_out_FIFO_data_out_valid),
	.data_out 		(address_out_FIFO_data_out		)
);

CSC_switch_FIFO  #(
	.DATA_WIDTH(DATA_WIDTH+COUNT_WIDTH)
	)
Data_out_FIFO( 
	.clock			(data_out_FIFO_clock			),
	.reset			(data_out_FIFO_reset			),
	.data_in_ready	(data_out_FIFO_data_in_ready	),
	.data_in_valid	(data_out_FIFO_data_in_valid	),
	.data_in 		(data_out_FIFO_data_in			),
	.data_out_ready	(data_out_FIFO_data_out_ready	),
	.data_out_valid	(data_out_FIFO_data_out_valid	),
	.data_out 		(data_out_FIFO_data_out			)
);


// ====================================================================	//
// 						 		Registers  								//
// ====================================================================	//
reg  [COUNT_WIDTH-1:0] 	csc_count; 
reg  [ADDR_WIDTH-1:0] 	csc_address; 
reg  [4:0] 				column_counter; 
reg  					zero_col;

reg   					one_vector_fin_reg; 
reg						end_flag_reg;
reg						first_col_flag;
reg	[4:0]				zero_count;
reg	[4:0]				count;

// reg						pre_zero_col;


// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
wire  one_col_fin 		= matrix_height == (csc_count + 'd1); 
wire  one_matrix_fin 	= matrix_width 	== (column_counter + 'd1); 

wire  meet_non_zero 		= data_in_FIFO_data_out != 'sd0; 
wire  current_zero_column 	= one_col_fin & (~meet_non_zero) & zero_col; 
wire  first_none_zero_value = meet_non_zero & zero_col; 
wire  first_col_all_zero 	= first_col_flag & (zero_count == count) & (data_in == 'd0);
wire  current_col_all_zero 	= (zero_count == count) & (data_in == 'd0);

// CSC encoding valid
wire  out_data_valid = meet_non_zero & data_in_FIFO_data_out_valid;
wire  out_addr_valid = (current_zero_column | first_none_zero_value) & data_in_FIFO_data_out_valid & (csc_address != 'd0); 

wire  end_flag = one_vector_fin_reg; 

// wire adjust_flag = (first_col_all_zero & count == matrix_height-'d1) | (current_col_all_zero & pre_zero_col & one_col_fin);
wire adjust_flag = (first_col_all_zero & count == matrix_height-'d1) | (current_col_all_zero & one_col_fin);


// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
// output
assign one_vector_done		= (address_out_valid == 'd1) & (address_out == 'd0);

assign data_in_ready 		= data_in_FIFO_data_in_valid; 

assign address_out_valid 	= clear_iact_SRAM ? 'd1 : address_out_FIFO_data_out_valid; 
assign address_out 			= clear_iact_SRAM ? 'd0 : address_out_FIFO_data_out; 

assign data_out_valid 		= clear_iact_SRAM ? 'd1 : data_out_FIFO_data_out_valid;
assign data_out 			= clear_iact_SRAM ? 'd0 : data_out_FIFO_data_out; 


// inter-connection
assign data_in_FIFO_clock 				= clock;                                                                 
assign data_in_FIFO_reset 				= reset;                                                                 
assign data_in_FIFO_data_in_valid 		= end_flag | end_flag_reg ? 'd0 : data_in_valid;                                                     
assign data_in_FIFO_data_in 			= end_flag | end_flag_reg ? 'd0 : (adjust_flag ? 'd1 : data_in);                                                            
assign data_in_FIFO_data_out_ready 		= 1'b1; // ~end_flag ? (~meet_non_zero ? (data_out_FIFO_data_in_ready & address_out_FIFO_data_in_ready) : 1'b1) : 1'b0;                                                          
                                   
assign address_out_FIFO_clock 			= clock;                                                       
assign address_out_FIFO_reset 			= reset; 
assign address_out_FIFO_data_in_valid 	= end_flag | end_flag_reg | out_addr_valid;                            
assign address_out_FIFO_data_in 		= end_flag_reg ? 'd0 : (current_zero_column ? (1<<ADDR_WIDTH)-1 : csc_address); 
assign address_out_FIFO_data_out_ready 	= address_out_ready;                                       
                                                                                              
assign data_out_FIFO_clock 				= clock;                                                    
assign data_out_FIFO_reset 				= reset;                                                    
assign data_out_FIFO_data_in_valid 		= end_flag | out_data_valid;                         
assign data_out_FIFO_data_in 			= end_flag ? 'd0 : adjust_flag ? ({data_in_FIFO_data_out, ((1<<COUNT_WIDTH)-1)}) : ({data_in_FIFO_data_out, csc_count});  
assign data_out_FIFO_data_out_ready 	= data_out_ready;                                       


// ====================================================================	//
// 						 		Sequential  							//
// ====================================================================	//
/*
always@(posedge clock) begin
	if(reset) begin 								
		pre_zero_col <= 'd0;						
	end 
	else if(one_col_fin) begin 						
		pre_zero_col <= current_zero_column;
	end 
end	
*/
	 
always@(posedge clock) begin
	if(reset) begin 								
		zero_count <= 'd0;						
	end 
	else if(end_flag) begin 						
		zero_count <= 'd0;
	end 
	else if(data_in_valid & (data_in == 'd0)) begin 						
		zero_count <= (zero_count == matrix_height-'d1) ? matrix_height-'d1 : zero_count + 'd1;
	end 
end

always@(posedge clock) begin
	if(reset) begin 								
		count <= 'd0;						
	end 
	else if(end_flag) begin 						
		count <= 'd0;
	end 
	else if(data_in_valid) begin 						
		count <= (count == matrix_height-'d1) ? matrix_height-'d1 : count + 'd1;
	end 
end	  

	   
always@(posedge clock) begin
	if(reset) begin 								
		first_col_flag <= 'd1; 							
	end 
	else if(end_flag) begin 						
		first_col_flag <= 'd1;
	end 
	else if(count == matrix_height-'d1) begin 				
		first_col_flag <= first_col_flag & 'd0;
	end
end	
				
				  
always@(posedge clock) begin                                                           
	if(reset) begin                                                                    
		csc_count <= 'd0; 
	end 
	else if(data_in_FIFO_data_out_ready & data_in_FIFO_data_out_valid) begin 
		if(one_col_fin) begin 
			csc_count <= 'd0;
		end 
		else begin
			csc_count <= csc_count + 'd1;
		end
	end
end

always@(posedge clock) begin
	if(reset) begin 								
		csc_address <= 'd0; 							
	end 
	else if(end_flag) begin 						
		csc_address <= 'd0;
	end 
	else if(out_data_valid) begin 				
		csc_address <= csc_address + 'd1;
	end
end

always@(posedge clock) begin
	if(reset) begin 								
		column_counter <= 'd0; 						
	end 
	else if(end_flag) begin 						
		column_counter <= 'd0;
	end 
	else if(one_col_fin) begin 					
		column_counter <= column_counter + 'd1;
	end
end

always@(posedge clock) begin
	if(reset) begin
		zero_col <= 1'b1;
	end
	else if(one_col_fin) begin
		zero_col <= 1'b1;
	end
	else if(meet_non_zero)begin
		zero_col <= 1'b0;
	end
end

always@(posedge clock) begin
	if(reset) begin
		one_vector_fin_reg <= 'd0;
	end
	else begin
		one_vector_fin_reg <= one_col_fin & one_matrix_fin; 		
	end
end
  
always@(posedge clock) begin
	if(reset) begin
		end_flag_reg <= 'd0;
	end
	else begin
		end_flag_reg <= end_flag; 		
	end						
end


endmodule

// ===== repo/FPGA_design/src/CSC_encoder/CSCSwitcher.v =====
module CSCSwitcher #(
	parameter ADDR_WIDTH 	= 7,
	parameter COUNT_WIDTH 	= 4,
	parameter DATA_WIDTH 	= 8
	)
(
	input         							clock,
	input         							reset,
	output        							data_in_ready,
	input         							data_in_valid,
	input 	signed 	[7:0]  					data_in,
					
	input         							address_out_ready,
	output        							address_out_valid,
	output [ADDR_WIDTH-1:0] 				address_out,
	input         							data_out_ready,
	output        							data_out_valid,
	output [DATA_WIDTH+COUNT_WIDTH-1:0] 	data_out,
					
	input  [4:0]  							matrix_height,
	input  [4:0]  							matrix_width,
	
	input									clear_iact_SRAM,
	
	output									one_vector_done
);


localparam DATA_IN_DATAWIDTH  = 8;


wire  								data_in_FIFO_clock; 
wire  								data_in_FIFO_reset; 
wire  								data_in_FIFO_data_in_ready; 
wire  								data_in_FIFO_data_in_valid; 
wire signed	[7:0] 					data_in_FIFO_data_in; 
wire  								data_in_FIFO_data_out_ready; 
wire  								data_in_FIFO_data_out_valid; 
wire signed	[7:0] 					data_in_FIFO_data_out; 
						
wire  								address_out_FIFO_clock; 
wire  								address_out_FIFO_reset; 
wire  								address_out_FIFO_data_in_ready; 
wire  								address_out_FIFO_data_in_valid; 
wire [ADDR_WIDTH-1:0] 				address_out_FIFO_data_in; 
wire  								address_out_FIFO_data_out_ready;
wire  								address_out_FIFO_data_out_valid; 
wire [ADDR_WIDTH-1:0] 				address_out_FIFO_data_out; 

wire  								data_out_FIFO_clock; 
wire  								data_out_FIFO_reset;
wire  								data_out_FIFO_data_in_ready; 
wire  								data_out_FIFO_data_in_valid; 
wire [DATA_WIDTH+COUNT_WIDTH-1:0] 	data_out_FIFO_data_in; 
wire  								data_out_FIFO_data_out_ready; 
wire  								data_out_FIFO_data_out_valid; 
wire [DATA_WIDTH+COUNT_WIDTH-1:0] 	data_out_FIFO_data_out; 


CSC_switch_FIFO  #(
	.DATA_WIDTH(DATA_IN_DATAWIDTH)
	)
Data_in_FIFO( 
	.clock			(data_in_FIFO_clock),
	.reset			(data_in_FIFO_reset),
	.data_in_ready	(data_in_FIFO_data_in_ready),
	.data_in_valid	(data_in_FIFO_data_in_valid),
	.data_in 		(data_in_FIFO_data_in),
	.data_out_ready	(data_in_FIFO_data_out_ready),
	.data_out_valid	(data_in_FIFO_data_out_valid),
	.data_out 		(data_in_FIFO_data_out)
);

CSC_switch_FIFO  #(
	.DATA_WIDTH(ADDR_WIDTH)
	)
Address_out_FIFO( 
	.clock			(address_out_FIFO_clock),
	.reset			(address_out_FIFO_reset),
	.data_in_ready	(address_out_FIFO_data_in_ready),
	.data_in_valid	(address_out_FIFO_data_in_valid),
	.data_in 		(address_out_FIFO_data_in),
	.data_out_ready	(address_out_FIFO_data_out_ready),
	.data_out_valid	(address_out_FIFO_data_out_valid),
	.data_out 		(address_out_FIFO_data_out)
);

CSC_switch_FIFO  #(
	.DATA_WIDTH(DATA_WIDTH+COUNT_WIDTH)
	)
Data_out_FIFO( 
	.clock			(data_out_FIFO_clock),
	.reset			(data_out_FIFO_reset),
	.data_in_ready	(data_out_FIFO_data_in_ready),
	.data_in_valid	(data_out_FIFO_data_in_valid),
	.data_in 		(data_out_FIFO_data_in),
	.data_out_ready	(data_out_FIFO_data_out_ready),
	.data_out_valid	(data_out_FIFO_data_out_valid),
	.data_out 		(data_out_FIFO_data_out)
);


reg  [COUNT_WIDTH-1:0] 	csc_count; 
reg  [ADDR_WIDTH-1:0] 	csc_address; 
reg  [4:0] 				column_counter; 
reg  					zero_col;

reg   		one_vector_fin_reg; 
reg			end_flag_reg;
reg			first_col_flag;
reg	[4:0]	zero_count;
reg	[4:0]	count;

reg			pre_zero_col;

wire  one_col_fin 		= matrix_height == (csc_count + 'd1); 
wire  one_matrix_fin 	= matrix_width 	== (column_counter + 'd1); 

wire  meet_non_zero 		= data_in_FIFO_data_out != 'sd0; 
wire  current_zero_column 	= one_col_fin & (~meet_non_zero) & zero_col; 
wire  first_none_zero_value = meet_non_zero & zero_col; 
wire  first_col_all_zero 	= first_col_flag & (zero_count == count) & (data_in == 'd0);
wire  current_col_all_zero 	= (zero_count == count) & (data_in == 'd0);

// CSC encoding valid
wire  out_data_valid = meet_non_zero & data_in_FIFO_data_out_valid;
wire  out_addr_valid = (current_zero_column | first_none_zero_value) & data_in_FIFO_data_out_valid & (csc_address != 'd0); 

wire  end_flag = one_vector_fin_reg; 

// output
assign one_vector_done		= (address_out_valid == 'd1) & (address_out == 'd0);

assign data_in_ready 		= data_in_FIFO_data_in_valid; 

assign address_out_valid 	= clear_iact_SRAM ? 'd1 : address_out_FIFO_data_out_valid; 
assign address_out 			= clear_iact_SRAM ? 'd0 : address_out_FIFO_data_out; 

assign data_out_valid 		= clear_iact_SRAM ? 'd1 : data_out_FIFO_data_out_valid;
assign data_out 			= clear_iact_SRAM ? 'd0 : data_out_FIFO_data_out; 

// wire adjust_flag = (first_col_all_zero & count == matrix_height-'d1) | (current_col_all_zero & pre_zero_col & one_col_fin);
wire adjust_flag = (first_col_all_zero & count == matrix_height-'d1) | (current_col_all_zero & one_col_fin);
// inter-connection
assign data_in_FIFO_clock 			= clock;                                                                 
assign data_in_FIFO_reset 			= reset;                                                                 
assign data_in_FIFO_data_in_valid 	= end_flag | end_flag_reg ? 'd0 : data_in_valid;                                                     
assign data_in_FIFO_data_in 		= end_flag | end_flag_reg ? 'd0 : (adjust_flag ? 'd1 : data_in);                                                            
assign data_in_FIFO_data_out_ready 	= 1'b1; // ~end_flag ? (~meet_non_zero ? (data_out_FIFO_data_in_ready & address_out_FIFO_data_in_ready) : 1'b1) : 1'b0;                                                          
                                   
assign address_out_FIFO_clock 			= clock;                                                       
assign address_out_FIFO_reset 			= reset; 
assign address_out_FIFO_data_in_valid 	= end_flag | end_flag_reg | out_addr_valid;                            
assign address_out_FIFO_data_in 		= end_flag_reg ? 'd0 : (current_zero_column ? (1<<ADDR_WIDTH)-1 : csc_address); 
assign address_out_FIFO_data_out_ready 	= address_out_ready;                                       
                                                                                              
assign data_out_FIFO_clock 			= clock;                                                    
assign data_out_FIFO_reset 			= reset;                                                    
assign data_out_FIFO_data_in_valid 	= end_flag | out_data_valid;                         
assign data_out_FIFO_data_in 		= end_flag ? 'd0 : adjust_flag ? ({data_in_FIFO_data_out, ((1<<COUNT_WIDTH)-1)}) : ({data_in_FIFO_data_out, csc_count});  
assign data_out_FIFO_data_out_ready = data_out_ready;                                       


always @(posedge clock) begin
	if (reset) begin 								
		pre_zero_col <= 'd0;						
	end 
	else if (one_col_fin) begin 						
		pre_zero_col <= current_zero_column;
	end 
end	

	 
always @(posedge clock) begin
	if (reset) begin 								
		zero_count <= 'd0;						
	end 
	else if (end_flag) begin 						
		zero_count <= 'd0;
	end 
	else if (data_in_valid & (data_in == 'd0)) begin 						
		zero_count <= (zero_count == matrix_height-'d1) ? matrix_height-'d1 : zero_count + 'd1;
	end 
end	   

always @(posedge clock) begin
	if (reset) begin 								
		count <= 'd0;						
	end 
	else if (end_flag) begin 						
		count <= 'd0;
	end 
	else if (data_in_valid) begin 						
		count <= (count == matrix_height-'d1) ? matrix_height-'d1 : count + 'd1;
	end 
end	  

	   
always @(posedge clock) begin
	if (reset) begin 								
		first_col_flag <= 'd1; 							
	end 
	else if (end_flag) begin 						
		first_col_flag <= 'd1;
	end 
	else if (count == matrix_height-'d1) begin 				
		first_col_flag <= first_col_flag & 'd0;
	end
end	
				
				  
always @(posedge clock) begin                                                           
	if (reset) begin                                                                    
		csc_count <= 'd0; 
	end 
	else if (data_in_FIFO_data_out_ready & data_in_FIFO_data_out_valid) begin 
		if (one_col_fin) begin 
			csc_count <= 'd0;
		end 
		else begin
			csc_count <= csc_count + 'd1;
		end
	end
end

always @(posedge clock) begin
	if (reset) begin 								
		csc_address <= 'd0; 							
	end 
	else if (end_flag) begin 						
		csc_address <= 'd0;
	end 
	else if (out_data_valid) begin 				
		csc_address <= csc_address + 'd1;
	end
end

always @(posedge clock) begin
	if (reset) begin 								
		column_counter <= 'd0; 						
	end 
	else if (end_flag) begin 						
		column_counter <= 'd0;
	end 
	else if (one_col_fin) begin 					
		column_counter <= column_counter + 'd1;
	end
end

always @(posedge clock) begin
	if(reset) begin
		zero_col <= 1'b1;
	end
	else if(one_col_fin) begin
		zero_col <= 1'b1;
	end
	else if(meet_non_zero)begin
		zero_col <= 1'b0;
	end
end

always @(posedge clock) begin
	if(reset) begin
		one_vector_fin_reg <= 'd0;
	end
	else begin
		one_vector_fin_reg <= one_col_fin & one_matrix_fin; 		
	end
end
  
always @(posedge clock) begin
	if(reset) begin
		end_flag_reg <= 'd0;
	end
	else begin
		end_flag_reg <= end_flag; 		
	end						
end


endmodule

// ===== repo/FPGA_design/src/CSC_encoder/CSC_switch_FIFO.v =====
module CSC_switch_FIFO #(
	parameter DATA_WIDTH = 8
	)
(
	input        				clock,
	input        				reset,
	output       				data_in_ready,
	input        				data_in_valid,
	input  [DATA_WIDTH-1:0] 	data_in,
	input        				data_out_ready,
	output      				data_out_valid,
	output [DATA_WIDTH-1:0] 	data_out
);

localparam BUFFER_DEPTH = 4;
	
reg [DATA_WIDTH-1:0] Buffer [0:BUFFER_DEPTH-1]; 

reg  maybe_full;
reg [1:0] Buffer_write_addr;
reg [1:0] Buffer_read_addr; 

wire [DATA_WIDTH-1:0] Buffer_read_out_data;

wire  Buffer_write_en;
wire  ptr_match = (Buffer_write_addr == Buffer_read_addr) ? 1'b1 : 1'b0;

wire  empty = ptr_match & ~maybe_full;
wire  full  = ptr_match &  maybe_full; 

wire  data_in_shake  = data_in_ready & data_in_valid; 
wire  data_out_shake = data_out_ready & data_out_valid; 

wire  data_in_en  = (empty && data_out_ready) ? 1'b0 : data_in_shake;
wire  data_out_en =  empty 				   	  ? 1'b0 : data_out_shake;

assign Buffer_read_out_data = Buffer[Buffer_read_addr]; 
assign data_in_ready  = data_out_ready | ~full; 
assign data_out_valid = data_in_valid  | ~empty;

assign data_out = empty ? data_in : Buffer_read_out_data; 
assign Buffer_write_en = empty ? (~data_out_ready & data_in_shake) : data_in_shake;

// write
integer i;
always @(posedge clock) begin
	if (Buffer_write_en) begin
		for(i=0; i<BUFFER_DEPTH; i=i+1) begin
			Buffer[Buffer_write_addr] <= 'd0; 
		end
	end
	else if (Buffer_write_en) begin
		Buffer[Buffer_write_addr] <= data_in; 
	end
end

// write addr
always @(posedge clock) begin
	if (reset) begin
		Buffer_write_addr <= 2'd0;
	end 
	else if (data_in_en) begin 
		Buffer_write_addr <= Buffer_write_addr + 2'd1;
	end
end

// read addr
always @(posedge clock) begin
	if (reset) begin
		Buffer_read_addr <= 2'd0;
	end 
	else if (data_out_en) begin 
		Buffer_read_addr <= Buffer_read_addr + 2'd1; 
	end
end

// flow control
always @(posedge clock) begin
	if (reset) begin
		maybe_full <= 1'd0;
	end 
	else if (data_in_en != data_out_en) begin 
		if (empty) begin
			if (data_out_ready) begin 
				maybe_full <= 1'd0; 
			end 
			else begin
				maybe_full <= data_in_shake;
			end
		end 
		else begin
			maybe_full <= data_in_shake;
		end
	end
end

endmodule

// ===== repo/FPGA_design/src/GLB_Cluster/GLB_Cluster.v =====
// ====================================================================================================== //
// This module is GLB cluster.
// GLB cluster module contains 9 iact SRAM and 3 psum SRAM.
// 9 iact SRAM connect to 9 PE in PE clusteer (one-to-one).
// 9 iact SRAM is used to support uni-cast in all layers.
// 9 iact SRAM is mainly to supply sufficient bandwidth.
// If SRAM BW is not a bottlenect for specific application, 9 iact SRAM can be scale down to 3. 
// 
// GLB cluster contains weight ports, but there is no SRAM to store weight data.
// weight data in GLB cluster will be directly pass to PE cluster and store in PE SPad (SRAM)
// ====================================================================================================== //


module GLB_Cluster (
	input        			clock,
	input        			reset,
	
	// iact SRAM Bank 0_0
	output 			       	iact_SRAM_Bank_0_0_address_in_ready,
	input  			       	iact_SRAM_Bank_0_0_address_in_valid,
	input  			[6:0]  	iact_SRAM_Bank_0_0_address_in,
	output 			       	iact_SRAM_Bank_0_0_data_in_ready,
	input  			       	iact_SRAM_Bank_0_0_data_in_valid,
	input  			[11:0] 	iact_SRAM_Bank_0_0_data_in,
												
	input  			       	iact_SRAM_Bank_0_0_address_out_ready,
	output 			       	iact_SRAM_Bank_0_0_address_out_valid,
	output 			[6:0]  	iact_SRAM_Bank_0_0_address_out,
	input  			       	iact_SRAM_Bank_0_0_data_out_ready,
	output 			       	iact_SRAM_Bank_0_0_data_out_valid,
	output 			[11:0] 	iact_SRAM_Bank_0_0_data_out,
												
	input  			       	iact_SRAM_Bank_0_0_write_en,
	output 			       	iact_SRAM_Bank_0_0_write_done,
	input  			       	iact_SRAM_Bank_0_0_read_en,
	input  			[9:0]  	iact_SRAM_Bank_0_0_read_addr,
	output 			       	iact_SRAM_Bank_0_0_read_done,		
	
	// iact SRAM Bank 0_1
	output 			      	iact_SRAM_Bank_0_1_address_in_ready,
	input  			      	iact_SRAM_Bank_0_1_address_in_valid,
	input  			[6:0] 	iact_SRAM_Bank_0_1_address_in,
	output 			      	iact_SRAM_Bank_0_1_data_in_ready,
	input  			      	iact_SRAM_Bank_0_1_data_in_valid,
	input  			[11:0]	iact_SRAM_Bank_0_1_data_in,
												
	input  			      	iact_SRAM_Bank_0_1_address_out_ready,
	output 			      	iact_SRAM_Bank_0_1_address_out_valid,
	output 			[6:0] 	iact_SRAM_Bank_0_1_address_out,
	input  			      	iact_SRAM_Bank_0_1_data_out_ready,
	output 			      	iact_SRAM_Bank_0_1_data_out_valid,
	output 			[11:0]	iact_SRAM_Bank_0_1_data_out,
												
	input  			      	iact_SRAM_Bank_0_1_write_en,
	output 			      	iact_SRAM_Bank_0_1_write_done,
	input  			      	iact_SRAM_Bank_0_1_read_en,
	input  			[9:0] 	iact_SRAM_Bank_0_1_read_addr,
	output 			      	iact_SRAM_Bank_0_1_read_done,		
		
	// iact SRAM Bank 0_2
	output 			       	iact_SRAM_Bank_0_2_address_in_ready,
	input  			       	iact_SRAM_Bank_0_2_address_in_valid,
	input  			[6:0]  	iact_SRAM_Bank_0_2_address_in,
	output 			       	iact_SRAM_Bank_0_2_data_in_ready,
	input  			       	iact_SRAM_Bank_0_2_data_in_valid,
	input  			[11:0] 	iact_SRAM_Bank_0_2_data_in,
												
	input  			       	iact_SRAM_Bank_0_2_address_out_ready,
	output 			       	iact_SRAM_Bank_0_2_address_out_valid,
	output 			[6:0]  	iact_SRAM_Bank_0_2_address_out,
	input  			       	iact_SRAM_Bank_0_2_data_out_ready,
	output 			       	iact_SRAM_Bank_0_2_data_out_valid,
	output 			[11:0] 	iact_SRAM_Bank_0_2_data_out,
												
	input  			       	iact_SRAM_Bank_0_2_write_en,
	output 			       	iact_SRAM_Bank_0_2_write_done,
	input  			       	iact_SRAM_Bank_0_2_read_en,
	input  			[9:0]  	iact_SRAM_Bank_0_2_read_addr,
	output 			       	iact_SRAM_Bank_0_2_read_done,	
	
	// iact SRAM Bank 1_0
	output			      	iact_SRAM_Bank_1_0_address_in_ready,
	input 			      	iact_SRAM_Bank_1_0_address_in_valid,
	input 			[6:0] 	iact_SRAM_Bank_1_0_address_in,
	output			      	iact_SRAM_Bank_1_0_data_in_ready,
	input 			      	iact_SRAM_Bank_1_0_data_in_valid,
	input 			[11:0]	iact_SRAM_Bank_1_0_data_in,
												
	input 			      	iact_SRAM_Bank_1_0_address_out_ready,
	output			      	iact_SRAM_Bank_1_0_address_out_valid,
	output			[6:0] 	iact_SRAM_Bank_1_0_address_out,
	input 			      	iact_SRAM_Bank_1_0_data_out_ready,
	output			      	iact_SRAM_Bank_1_0_data_out_valid,
	output			[11:0]	iact_SRAM_Bank_1_0_data_out,
												
	input 			      	iact_SRAM_Bank_1_0_write_en,
	output			      	iact_SRAM_Bank_1_0_write_done,
	input 			      	iact_SRAM_Bank_1_0_read_en,
	input 			[9:0] 	iact_SRAM_Bank_1_0_read_addr,
	output			      	iact_SRAM_Bank_1_0_read_done,		
								
	// iact SRAM Bank 1_1       
	output			       	iact_SRAM_Bank_1_1_address_in_ready,
	input 			       	iact_SRAM_Bank_1_1_address_in_valid,
	input 			[6:0]  	iact_SRAM_Bank_1_1_address_in,
	output			       	iact_SRAM_Bank_1_1_data_in_ready,
	input 			       	iact_SRAM_Bank_1_1_data_in_valid,
	input 			[11:0] 	iact_SRAM_Bank_1_1_data_in,
												
	input 			       	iact_SRAM_Bank_1_1_address_out_ready,
	output			       	iact_SRAM_Bank_1_1_address_out_valid,
	output			[6:0]  	iact_SRAM_Bank_1_1_address_out,
	input 			       	iact_SRAM_Bank_1_1_data_out_ready,
	output			       	iact_SRAM_Bank_1_1_data_out_valid,
	output			[11:0] 	iact_SRAM_Bank_1_1_data_out,
												
	input 			       	iact_SRAM_Bank_1_1_write_en,
	output			       	iact_SRAM_Bank_1_1_write_done,
	input 			       	iact_SRAM_Bank_1_1_read_en,
	input 			[9:0]  	iact_SRAM_Bank_1_1_read_addr,
	output			       	iact_SRAM_Bank_1_1_read_done,		
								 
	// iact SRAM Bank 1_2        
	output 			       	iact_SRAM_Bank_1_2_address_in_ready,
	input  			       	iact_SRAM_Bank_1_2_address_in_valid,
	input  			[6:0]  	iact_SRAM_Bank_1_2_address_in,
	output 			       	iact_SRAM_Bank_1_2_data_in_ready,
	input  			       	iact_SRAM_Bank_1_2_data_in_valid,
	input  			[11:0] 	iact_SRAM_Bank_1_2_data_in,
												
	input  			       	iact_SRAM_Bank_1_2_address_out_ready,
	output 			       	iact_SRAM_Bank_1_2_address_out_valid,
	output 			[6:0]  	iact_SRAM_Bank_1_2_address_out,
	input  			       	iact_SRAM_Bank_1_2_data_out_ready,
	output 			       	iact_SRAM_Bank_1_2_data_out_valid,
	output 			[11:0] 	iact_SRAM_Bank_1_2_data_out,
												
	input  			       	iact_SRAM_Bank_1_2_write_en,
	output 			       	iact_SRAM_Bank_1_2_write_done,
	input  			       	iact_SRAM_Bank_1_2_read_en,
	input  			[9:0]  	iact_SRAM_Bank_1_2_read_addr,
	output 			       	iact_SRAM_Bank_1_2_read_done,	


	// iact SRAM Bank 2_0
	output 			       	iact_SRAM_Bank_2_0_address_in_ready,
	input  			       	iact_SRAM_Bank_2_0_address_in_valid,
	input  			[6:0]  	iact_SRAM_Bank_2_0_address_in,
	output 			       	iact_SRAM_Bank_2_0_data_in_ready,
	input  			       	iact_SRAM_Bank_2_0_data_in_valid,
	input  			[11:0] 	iact_SRAM_Bank_2_0_data_in,
												
	input  			       	iact_SRAM_Bank_2_0_address_out_ready,
	output 			       	iact_SRAM_Bank_2_0_address_out_valid,
	output 			[6:0]  	iact_SRAM_Bank_2_0_address_out,
	input  			       	iact_SRAM_Bank_2_0_data_out_ready,
	output 			       	iact_SRAM_Bank_2_0_data_out_valid,
	output 			[11:0] 	iact_SRAM_Bank_2_0_data_out,
												
	input  			       	iact_SRAM_Bank_2_0_write_en,
	output 			       	iact_SRAM_Bank_2_0_write_done,
	input  			       	iact_SRAM_Bank_2_0_read_en,
	input  			[9:0]  	iact_SRAM_Bank_2_0_read_addr,
	output 			       	iact_SRAM_Bank_2_0_read_done,		
								 
	// iact SRAM Bank 2_1        
	output 			       	iact_SRAM_Bank_2_1_address_in_ready,
	input  			       	iact_SRAM_Bank_2_1_address_in_valid,
	input  			[6:0]  	iact_SRAM_Bank_2_1_address_in,
	output 			       	iact_SRAM_Bank_2_1_data_in_ready,
	input  			       	iact_SRAM_Bank_2_1_data_in_valid,
	input  			[11:0] 	iact_SRAM_Bank_2_1_data_in,
												
	input  			       	iact_SRAM_Bank_2_1_address_out_ready,
	output 			       	iact_SRAM_Bank_2_1_address_out_valid,
	output 			[6:0]  	iact_SRAM_Bank_2_1_address_out,
	input  			       	iact_SRAM_Bank_2_1_data_out_ready,
	output 			       	iact_SRAM_Bank_2_1_data_out_valid,
	output 			[11:0] 	iact_SRAM_Bank_2_1_data_out,
												
	input  			       	iact_SRAM_Bank_2_1_write_en,
	output 			       	iact_SRAM_Bank_2_1_write_done,
	input  			       	iact_SRAM_Bank_2_1_read_en,
	input  			[9:0]  	iact_SRAM_Bank_2_1_read_addr,
	output 			       	iact_SRAM_Bank_2_1_read_done,		
								
	// iact SRAM Bank 2_2        
	output 			       	iact_SRAM_Bank_2_2_address_in_ready,
	input  			       	iact_SRAM_Bank_2_2_address_in_valid,
	input  			[6:0]  	iact_SRAM_Bank_2_2_address_in,
	output 			       	iact_SRAM_Bank_2_2_data_in_ready,
	input  			       	iact_SRAM_Bank_2_2_data_in_valid,
	input  			[11:0] 	iact_SRAM_Bank_2_2_data_in,
												
	input  			       	iact_SRAM_Bank_2_2_address_out_ready,
	output 			       	iact_SRAM_Bank_2_2_address_out_valid,
	output 			[6:0]  	iact_SRAM_Bank_2_2_address_out,
	input  			       	iact_SRAM_Bank_2_2_data_out_ready,
	output 			       	iact_SRAM_Bank_2_2_data_out_valid,
	output 			[11:0] 	iact_SRAM_Bank_2_2_data_out,
												
	input  			       	iact_SRAM_Bank_2_2_write_en,
	output 			       	iact_SRAM_Bank_2_2_write_done,
	input  			       	iact_SRAM_Bank_2_2_read_en,
	input  			[9:0]  	iact_SRAM_Bank_2_2_read_addr,
	output 			       	iact_SRAM_Bank_2_2_read_done,	
	
	
	// There is no SRAM to store weights from TOP DRAM
	// weights ares directly stored in PE spad
	output 			       	weight_0_address_in_ready,
	input  			       	weight_0_address_in_valid,
	input  			[7:0]  	weight_0_address_in,
	output 			       	weight_0_data_in_ready,
	input  			       	weight_0_data_in_valid,
	input  			[12:0] 	weight_0_data_in,
					
	input  			       	weight_0_address_out_ready,
	output 			       	weight_0_address_out_valid,
	output 			[7:0]  	weight_0_address_out,
	input  			       	weight_0_data_out_ready,
	output 			       	weight_0_data_out_valid,
	output 			[12:0] 	weight_0_data_out,
					
	output 			       	weight_1_address_in_ready,
	input  			       	weight_1_address_in_valid,
	input  			[7:0]  	weight_1_address_in,
	output 			       	weight_1_data_in_ready,
	input  			       	weight_1_data_in_valid,
	input  			[12:0] 	weight_1_data_in,
										
	input  			       	weight_1_address_out_ready,
	output 			       	weight_1_address_out_valid,
	output 			[7:0]  	weight_1_address_out,
	input  			       	weight_1_data_out_ready,
	output 			       	weight_1_data_out_valid,
	output 			[12:0] 	weight_1_data_out,
					
	output 			       	weight_2_address_in_ready,
	input  			       	weight_2_address_in_valid,
	input  			[7:0]  	weight_2_address_in,
	output 			       	weight_2_data_in_ready,
	input  			       	weight_2_data_in_valid,
	input  			[12:0] 	weight_2_data_in,
										
	input  			       	weight_2_address_out_ready,
	output 			       	weight_2_address_out_valid,
	output 			[7:0]  	weight_2_address_out,
	input  			       	weight_2_data_out_ready,
	output 			       	weight_2_data_out_valid,
	output 			[12:0] 	weight_2_data_out,
	
	// psum SRAM Bank 0
	output        			psum_SRAM_Bank_0_data_in_ready,        
	input         			psum_SRAM_Bank_0_data_in_valid,        
	input 	signed  [20:0] 	psum_SRAM_Bank_0_data_in,  
