// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
localparam PSUM_FROM_SOU 	= 1'b0;
localparam PSUM_FROM_ROUTER = 1'b1;


// ====================================================================	//
// 						 		Registers  								//
// ====================================================================	//
reg  PE_0_0_cal_fin_reg; 
reg  PE_0_1_cal_fin_reg; 
reg  PE_0_2_cal_fin_reg; 
reg  PE_1_0_cal_fin_reg; 
reg  PE_1_1_cal_fin_reg; 
reg  PE_1_2_cal_fin_reg; 
reg  PE_2_0_cal_fin_reg; 
reg  PE_2_1_cal_fin_reg; 
reg  PE_2_2_cal_fin_reg; 

reg  PE_0_0_write_fin_reg;
reg  PE_0_1_write_fin_reg;
reg  PE_0_2_write_fin_reg;        
reg  PE_1_0_write_fin_reg;
reg  PE_1_1_write_fin_reg;
reg  PE_1_2_write_fin_reg;        
reg  PE_2_0_write_fin_reg;
reg  PE_2_1_write_fin_reg;
reg  PE_2_2_write_fin_reg;


// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
// output signals
assign all_write_fin= 	PE_0_0_write_fin_reg & PE_0_1_write_fin_reg & PE_0_2_write_fin_reg & 
						PE_1_0_write_fin_reg & PE_1_1_write_fin_reg & PE_1_2_write_fin_reg & 
						PE_2_0_write_fin_reg & PE_2_1_write_fin_reg & PE_2_2_write_fin_reg; 

assign all_cal_fin	= 	PE_0_0_cal_fin_reg & PE_0_1_cal_fin_reg & PE_0_2_cal_fin_reg & 
						PE_1_0_cal_fin_reg & PE_1_1_cal_fin_reg & PE_1_2_cal_fin_reg & 
						PE_2_0_cal_fin_reg & PE_2_1_cal_fin_reg & PE_2_2_cal_fin_reg; 


assign psum_0_in_ready 	= (psum_data_in_sel == PSUM_FROM_ROUTER) & PE_2_0_psum_in_ready; 
assign psum_1_in_ready 	= (psum_data_in_sel == PSUM_FROM_ROUTER) & PE_2_1_psum_in_ready; 
assign psum_2_in_ready 	= (psum_data_in_sel == PSUM_FROM_ROUTER) & PE_2_2_psum_in_ready; 

assign psum_0_out_valid	= PE_0_0_psum_out_valid;  
assign psum_1_out_valid	= PE_0_1_psum_out_valid;  
assign psum_2_out_valid	= PE_0_2_psum_out_valid;  

assign psum_0_out 		= PE_0_0_psum_out; 
assign psum_1_out 		= PE_0_1_psum_out; 
assign psum_2_out 		= PE_0_2_psum_out; 

assign psum_0_in_from_south_ready = (psum_data_in_sel == PSUM_FROM_ROUTER) ? 1'b0 : PE_2_0_psum_in_ready; 
assign psum_1_in_from_south_ready = (psum_data_in_sel == PSUM_FROM_ROUTER) ? 1'b0 : PE_2_1_psum_in_ready; 
assign psum_2_in_from_south_ready = (psum_data_in_sel == PSUM_FROM_ROUTER) ? 1'b0 : PE_2_2_psum_in_ready; 


// inter-connection
assign PE_0_0_psum_in_valid 			= PE_1_0_psum_out_valid; 
assign PE_0_0_psum_in 					= PE_1_0_psum_out; 
assign PE_0_0_psum_out_ready 			= psum_0_out_ready;
assign PE_0_0_weight_address_in_valid 	= weight_0_0_address_in_valid; 
assign PE_0_0_weight_address_in 		= weight_0_0_address_in; 
assign PE_0_0_weight_data_in_valid 		= weight_0_0_data_in_valid; 
assign PE_0_0_weight_data_in 			= weight_0_0_data_in; 
assign PE_0_0_psum_enq_en 				= psum_load_en; 
assign PE_0_0_do_load_en 				= do_en & ~PE_0_0_cal_fin_reg; 
assign PE_0_0_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_0_0_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_0_1_psum_in_valid 			= PE_1_1_psum_out_valid;
assign PE_0_1_psum_in 					= PE_1_1_psum_out; 
assign PE_0_1_psum_out_ready 			= psum_1_out_ready;
assign PE_0_1_weight_address_in_valid 	= weight_0_1_address_in_valid; 
assign PE_0_1_weight_address_in 		= weight_0_1_address_in; 
assign PE_0_1_weight_data_in_valid 		= weight_0_1_data_in_valid; 
assign PE_0_1_weight_data_in 			= weight_0_1_data_in; 
assign PE_0_1_psum_enq_en 				= psum_load_en; 
assign PE_0_1_do_load_en 				= do_en & ~PE_0_1_cal_fin_reg; 
assign PE_0_1_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_0_1_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_0_2_psum_in_valid 			= PE_1_2_psum_out_valid;
assign PE_0_2_psum_in 					= PE_1_2_psum_out; 
assign PE_0_2_psum_out_ready 			= psum_2_out_ready;
assign PE_0_2_weight_address_in_valid 	= weight_0_2_address_in_valid; 
assign PE_0_2_weight_address_in 		= weight_0_2_address_in; 
assign PE_0_2_weight_data_in_valid 		= weight_0_2_data_in_valid; 
assign PE_0_2_weight_data_in 			= weight_0_2_data_in; 
assign PE_0_2_psum_enq_en 				= psum_load_en; 
assign PE_0_2_do_load_en 				= do_en & ~PE_0_2_cal_fin_reg; 
assign PE_0_2_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_0_2_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_1_0_psum_in_valid 			= PE_2_0_psum_out_valid;
assign PE_1_0_psum_in 					= PE_2_0_psum_out; 
assign PE_1_0_psum_out_ready 			= PE_0_0_psum_in_ready;
assign PE_1_0_weight_address_in_valid 	= weight_1_0_address_in_valid; 
assign PE_1_0_weight_address_in 		= weight_1_0_address_in; 
assign PE_1_0_weight_data_in_valid 		= weight_1_0_data_in_valid; 
assign PE_1_0_weight_data_in 			= weight_1_0_data_in; 
assign PE_1_0_psum_enq_en 				= psum_load_en; 
assign PE_1_0_do_load_en 				= do_en & ~PE_1_0_cal_fin_reg; 
assign PE_1_0_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_1_0_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_1_1_psum_in_valid 			= PE_2_1_psum_out_valid;
assign PE_1_1_psum_in 					= PE_2_1_psum_out; 
assign PE_1_1_psum_out_ready 			= PE_0_1_psum_in_ready;
assign PE_1_1_weight_address_in_valid 	= weight_1_1_address_in_valid;                        
assign PE_1_1_weight_address_in 		= weight_1_1_address_in; 
assign PE_1_1_weight_data_in_valid 		= weight_1_1_data_in_valid; 
assign PE_1_1_weight_data_in 			= weight_1_1_data_in; 
assign PE_1_1_psum_enq_en 				= psum_load_en; 
assign PE_1_1_do_load_en 				= do_en & ~PE_1_1_cal_fin_reg; 
assign PE_1_1_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_1_1_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_1_2_psum_in_valid 			= PE_2_2_psum_out_valid;
assign PE_1_2_psum_in 					= PE_2_2_psum_out; 
assign PE_1_2_psum_out_ready 			= PE_0_2_psum_in_ready;
assign PE_1_2_weight_address_in_valid 	= weight_1_2_address_in_valid; 
assign PE_1_2_weight_address_in 		= weight_1_2_address_in; 
assign PE_1_2_weight_data_in_valid 		= weight_1_2_data_in_valid; 
assign PE_1_2_weight_data_in 			= weight_1_2_data_in; 
assign PE_1_2_psum_enq_en 				= psum_load_en; 
assign PE_1_2_do_load_en 				= do_en & ~PE_1_2_cal_fin_reg; 
assign PE_1_2_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_1_2_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_2_0_psum_in_valid 			= (psum_data_in_sel == PSUM_FROM_ROUTER) ? psum_0_in_valid : psum_0_in_from_south_valid; 
assign PE_2_0_psum_in 					= (psum_data_in_sel == PSUM_FROM_ROUTER) ? psum_0_in : psum_0_in_from_south; 
assign PE_2_0_psum_out_ready 			= PE_1_0_psum_in_ready;
assign PE_2_0_weight_address_in_valid 	= weight_2_0_address_in_valid; 
assign PE_2_0_weight_address_in 		= weight_2_0_address_in; 
assign PE_2_0_weight_data_in_valid 		= weight_2_0_data_in_valid; 
assign PE_2_0_weight_data_in 			= weight_2_0_data_in; 
assign PE_2_0_psum_enq_en 				= psum_load_en; 
assign PE_2_0_do_load_en 				= do_en & ~PE_2_0_cal_fin_reg;  
assign PE_2_0_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_2_0_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_2_1_psum_in_valid 			= (psum_data_in_sel == PSUM_FROM_ROUTER) ? psum_1_in_valid : psum_1_in_from_south_valid; 
assign PE_2_1_psum_in 					= (psum_data_in_sel == PSUM_FROM_ROUTER) ? psum_1_in : psum_1_in_from_south; 
assign PE_2_1_psum_out_ready 			= PE_1_1_psum_in_ready;
assign PE_2_1_weight_address_in_valid 	= weight_2_1_address_in_valid; 
assign PE_2_1_weight_address_in 		= weight_2_1_address_in; 
assign PE_2_1_weight_data_in_valid 		= weight_2_1_data_in_valid; 
assign PE_2_1_weight_data_in 			= weight_2_1_data_in; 
assign PE_2_1_psum_enq_en 				= psum_load_en; 
assign PE_2_1_do_load_en 				= do_en & ~PE_2_1_cal_fin_reg;  
assign PE_2_1_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_2_1_weight_write_fin_clear	= weight_write_fin_clear;

assign PE_2_2_psum_in_valid 			= (psum_data_in_sel == PSUM_FROM_ROUTER) ? psum_2_in_valid 	: psum_2_in_from_south_valid; 
assign PE_2_2_psum_in 					= (psum_data_in_sel == PSUM_FROM_ROUTER) ? psum_2_in 		: psum_2_in_from_south; 
assign PE_2_2_psum_out_ready 			= PE_1_2_psum_in_ready;
assign PE_2_2_weight_address_in_valid 	= weight_2_2_address_in_valid; 
assign PE_2_2_weight_address_in 		= weight_2_2_address_in; 
assign PE_2_2_weight_data_in_valid 		= weight_2_2_data_in_valid; 
assign PE_2_2_weight_data_in 			= weight_2_2_data_in; 
assign PE_2_2_psum_enq_en 				= psum_load_en; 
assign PE_2_2_do_load_en 				= do_en & ~PE_2_2_cal_fin_reg;  
assign PE_2_2_iact_write_fin_clear		= iact_write_fin_clear;
assign PE_2_2_weight_write_fin_clear	= weight_write_fin_clear;


// ====================================================================	//
// 						 		Sequential  							//
// ====================================================================	//
always@(posedge clock) begin
	if(reset) begin 
		PE_0_0_write_fin_reg <= 1'b0; 
		PE_0_1_write_fin_reg <= 1'b0;
		PE_0_2_write_fin_reg <= 1'b0;
						
		PE_1_0_write_fin_reg <= 1'b0;
		PE_1_1_write_fin_reg <= 1'b0;
		PE_1_2_write_fin_reg <= 1'b0;
						
		PE_2_0_write_fin_reg <= 1'b0;
		PE_2_1_write_fin_reg <= 1'b0;
		PE_2_2_write_fin_reg <= 1'b0;
	end 
	else if(all_cal_fin) begin 
		PE_0_0_write_fin_reg <= 1'b0; 
		PE_0_1_write_fin_reg <= 1'b0;
		PE_0_2_write_fin_reg <= 1'b0;
						
		PE_1_0_write_fin_reg <= 1'b0;
		PE_1_1_write_fin_reg <= 1'b0;
		PE_1_2_write_fin_reg <= 1'b0;
						
		PE_2_0_write_fin_reg <= 1'b0;
		PE_2_1_write_fin_reg <= 1'b0;
		PE_2_2_write_fin_reg <= 1'b0;
	end 
	else begin
		PE_0_0_write_fin_reg <= PE_0_0_write_fin | PE_0_0_write_fin_reg | PE_0_0_disable;        
		PE_0_1_write_fin_reg <= PE_0_1_write_fin | PE_0_1_write_fin_reg | PE_0_1_disable;        
		PE_0_2_write_fin_reg <= PE_0_2_write_fin | PE_0_2_write_fin_reg | PE_0_2_disable;          
		                                                                        
		PE_1_0_write_fin_reg <= PE_1_0_write_fin | PE_1_0_write_fin_reg | PE_1_0_disable;        
		PE_1_1_write_fin_reg <= PE_1_1_write_fin | PE_1_1_write_fin_reg | PE_1_1_disable;        
		PE_1_2_write_fin_reg <= PE_1_2_write_fin | PE_1_2_write_fin_reg | PE_1_2_disable;         
		                                                                        
		PE_2_0_write_fin_reg <= PE_2_0_write_fin | PE_2_0_write_fin_reg | PE_2_0_disable;        
		PE_2_1_write_fin_reg <= PE_2_1_write_fin | PE_2_1_write_fin_reg | PE_2_1_disable;        
		PE_2_2_write_fin_reg <= PE_2_2_write_fin | PE_2_2_write_fin_reg | PE_2_2_disable;
	end
end


always@(posedge clock) begin
	if(reset) begin 
		PE_0_0_cal_fin_reg <= 1'b0; 
		PE_0_1_cal_fin_reg <= 1'b0;
		PE_0_2_cal_fin_reg <= 1'b0;
						
		PE_1_0_cal_fin_reg <= 1'b0;
		PE_1_1_cal_fin_reg <= 1'b0;
		PE_1_2_cal_fin_reg <= 1'b0;
						
		PE_2_0_cal_fin_reg <= 1'b0;
		PE_2_1_cal_fin_reg <= 1'b0;
		PE_2_2_cal_fin_reg <= 1'b0;
	end 
	else if(all_cal_fin) begin 
		PE_0_0_cal_fin_reg <= 1'b0; 
		PE_0_1_cal_fin_reg <= 1'b0;
		PE_0_2_cal_fin_reg <= 1'b0;
						
		PE_1_0_cal_fin_reg <= 1'b0;
		PE_1_1_cal_fin_reg <= 1'b0;
		PE_1_2_cal_fin_reg <= 1'b0;
						
		PE_2_0_cal_fin_reg <= 1'b0;
		PE_2_1_cal_fin_reg <= 1'b0;
		PE_2_2_cal_fin_reg <= 1'b0;
	end 
	else begin
		PE_0_0_cal_fin_reg <= PE_0_0_cal_fin | PE_0_0_cal_fin_reg | PE_0_0_disable;        
		PE_0_1_cal_fin_reg <= PE_0_1_cal_fin | PE_0_1_cal_fin_reg | PE_0_1_disable;        
		PE_0_2_cal_fin_reg <= PE_0_2_cal_fin | PE_0_2_cal_fin_reg | PE_0_2_disable;          
		                                                                  
		PE_1_0_cal_fin_reg <= PE_1_0_cal_fin | PE_1_0_cal_fin_reg | PE_1_0_disable;        
		PE_1_1_cal_fin_reg <= PE_1_1_cal_fin | PE_1_1_cal_fin_reg | PE_1_1_disable;        
		PE_1_2_cal_fin_reg <= PE_1_2_cal_fin | PE_1_2_cal_fin_reg | PE_1_2_disable;         
		                                                                  
		PE_2_0_cal_fin_reg <= PE_2_0_cal_fin | PE_2_0_cal_fin_reg | PE_2_0_disable;        
		PE_2_1_cal_fin_reg <= PE_2_1_cal_fin | PE_2_1_cal_fin_reg | PE_2_1_disable;        
		PE_2_2_cal_fin_reg <= PE_2_2_cal_fin | PE_2_2_cal_fin_reg | PE_2_2_disable;
	end
end


endmodule

// ===== repo/FPGA_design/src/PE_Cluster/PE/PE_data_FIFO.v =====
// ====================================================================================================== //
// This module is the FIFO for the IO of data of PE.
// This FIFO is used to buffer the IO of data between the inside of PE and outside of PE for asynchromous case.  
// 
// TODO : For FPGA implementation, use FIFO IP to replace this module
// ====================================================================================================== //


module PE_data_FIFO #(
	parameter DATA_IN_WIDTH = 4
	)
(
	input        				clock,
	input        				reset,
	// data signals
	output       				data_in_ready, 
	input        				data_in_valid,
	input  [DATA_IN_WIDTH-1:0] 	data_in,
	output       				data_out_valid, 
	output [DATA_IN_WIDTH-1:0] 	data_out
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam BUFFER_DEPTH = 4;


// ================================================	//
// 					 Registers  					//
// ================================================	//
reg [DATA_IN_WIDTH-1:0] buffer [0:BUFFER_DEPTH-1];
reg maybe_full;

reg [1:0] buffer_read_addr;
reg [1:0] buffer_write_addr;


// ================================================	//
// 					 	Wires  						//
// ================================================	//
wire [DATA_IN_WIDTH-1:0] buffer_data_out;

wire ptr_match 	= (buffer_write_addr == buffer_read_addr) ? 1'b1 : 1'b0;
wire empty 		= ptr_match & ~maybe_full;

wire write_en 	= empty ? 1'b0 : data_in_valid;
wire read_en  	= empty ? 1'b0 : data_out_valid;


// ================================================	//
// 					 Combination  					//
// ================================================	//
assign buffer_data_out 	= buffer[buffer_read_addr];
assign data_in_ready 	= 1'b1;
assign data_out_valid 	= data_in_valid | (~empty);
assign data_out 		= empty ? data_in : buffer_data_out;


// ================================================	//
// 					 Sequential  					//
// ================================================	//
integer i;
always@(posedge clock) begin
	if(reset) begin
		for(i=0; i<BUFFER_DEPTH; i=i+1) begin
			buffer[i] <= 'd0;
		end
	end
	else if(~empty & data_in_valid) begin
		buffer[buffer_write_addr] <= data_in;
	end
end

always@(posedge clock) begin
	if(reset) begin
		buffer_write_addr <= 'd0;
	end 
	else if(write_en) begin
		buffer_write_addr <= buffer_write_addr + 'd1;
	end
end
	
always@(posedge clock) begin	
	if(reset) begin
		buffer_read_addr <= 'd0;
	end 
	else if(read_en) begin
		buffer_read_addr <= buffer_read_addr + 'd1;
	end
end

always@(posedge clock) begin
	if(reset) begin
		maybe_full <= 1'b0;
	end 
	else if(write_en != read_en) begin
		if(empty) begin
			maybe_full <= 1'b0;
		end 
		else begin
			maybe_full <= data_in_valid;
		end
	end
end

endmodule
// ===== repo/FPGA_design/src/PE_Cluster/PE/PE_psum_FIFO.v =====
// ====================================================================================================== //
// This module is the FIFO for the input and output of psum data.
// This FIFO is used to buffer the IO of data between the inside of PE and outside of PE for asynchromous case.  
// 
// TODO : For FPGA implementation, use FIFO IP to replace this module.
// 
// note : the module should be disbalem because psum is always synchromous to inside and outside of PE.
// ====================================================================================================== //


module PE_psum_FIFO(
	input         			clock,
	input         			reset,
	// data signals
	output        			data_in_ready,
	input         			data_in_valid,
	input 	signed [20:0] 	data_in,
	input         			data_out_ready,
	output        			data_out_valid,
	output 	signed [20:0] 	data_out
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam BUFFER_DEPTH = 4;


// ================================================	//
// 					 Registers  					//
// ================================================	//
reg signed [20:0] buffer [0:BUFFER_DEPTH-1];

reg [1:0] buffer_read_addr;
reg [1:0] buffer_write_addr;

reg maybe_full;


// ================================================	//
// 					 	Wires  						//
// ================================================	//
wire ptr_match 		= (buffer_write_addr == buffer_read_addr) ? 1'b1 : 1'b0;
wire empty 			= 'd1; // ptr_match & ~maybe_full;
wire full  			= ptr_match &  maybe_full;

wire data_in_shake  = data_in_ready  & data_in_valid;
wire data_out_shake = data_out_ready & data_out_valid;

wire write_en 		= empty ? (~data_out_ready & data_in_shake) : data_in_shake;
wire read_en  		= empty ? 1'b0 : data_out_shake;

wire signed [20:0] buffer_data_out_wire = buffer[buffer_read_addr];


// ================================================	//
// 					 Combination  					//
// ================================================	//
assign data_in_ready 	= data_out_ready | ~full;
assign data_out_valid 	= data_in_valid  | ~empty;
assign data_out 		= empty ? data_in : buffer_data_out_wire;


// ================================================	//
// 					 Sequential  					//
// ================================================	//
integer i;
always@(posedge clock) begin
	if(reset) begin
		for(i=0; i<BUFFER_DEPTH; i=i+1) begin
			buffer[i] <= 21'sd0;
		end
	end
    else if (write_en) begin
		buffer[buffer_write_addr] <= data_in;
    end
end

always@(posedge clock) begin
    if (reset) begin
		buffer_write_addr <= 2'd0;
    end 
	else if (write_en) begin
		buffer_write_addr <= buffer_write_addr + 2'd1;
    end
end	

always@(posedge clock) begin
    if (reset) begin
		buffer_read_addr <= 2'd0;
    end 
	else if (read_en) begin
		buffer_read_addr <= buffer_read_addr + 2'd1;
    end
end

always@(posedge clock) begin
    if (reset) begin
		maybe_full <= 1'b0;
    end 
	else if (write_en != read_en) begin
		if (empty) begin
			if (data_out_ready) begin
				maybe_full <= 1'b0;
			end 
			else begin
				maybe_full <= data_in_shake;
			end
		end 
		else begin
			maybe_full <= data_in_shake;
		end
    end
end


endmodule


// ===== repo/FPGA_design/src/PE_Cluster/PE/Processing_Element_Controller.v =====
// ====================================================================================================== //
// This module is the controller for PE module in Top-level.
// PE controller contains 3 state, IDLE, LOAD, CAL
// This module is the continuation point of form top signals and output control signals.
// ====================================================================================================== //


module Processing_Element_Controller (
	input   clock,
	input   reset,
	
	output  mac_en,
	output  from_top_psum_enq_en,
	output  from_top_do_load_en,
	input   from_top_cal_fin,
	
	input   top_psum_enq_en,
	input   top_do_load_en,
	output  top_cal_fin,
	input   top_write_fin
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam IDLE = 2'b00;
localparam LOAD = 2'b01;
localparam CAL  = 2'b10;


// ================================================	//
// 				 Registers & Wires  				//
// ================================================	//
reg [1:0] PE_state, next_PE_state;


// ================================================	//
// 					 Combination  					//
// ================================================	//
assign mac_en 				= (PE_state == CAL) ? 1'b1 : 1'b0;
assign from_top_psum_enq_en = top_psum_enq_en;
assign from_top_do_load_en  = top_do_load_en;
assign top_cal_fin 			= from_top_cal_fin & (PE_state == CAL);

// next state logic
always@(*) begin
	case(PE_state)
		IDLE    : next_PE_state = top_do_load_en 	? LOAD : IDLE;
		LOAD    : next_PE_state = top_write_fin 	? CAL  : LOAD;
		CAL     : next_PE_state = from_top_cal_fin 	? IDLE : CAL;
		default : next_PE_state = IDLE;
	endcase
end


// ================================================	//
// 					 Sequential  					//
// ================================================	//
// FSM
always@(posedge clock) begin
    if(reset) begin
		PE_state <= IDLE;
	end
	else begin
		PE_state <= next_PE_state;
	end
end


endmodule
// ===== repo/FPGA_design/src/PE_Cluster/PE/Processing_Element_core.v =====
// ====================================================================================================== //
// This module is the integration for all SPad in PE.
// PE_Pad is the core of PE, which is contains all control and datapath.
// This design is based on 5-stage pipeline architecture.
// 
// TODO : read later data should be only one cycle
// TODO : optimaize the state machine converted condition
// ====================================================================================================== //


module Processing_Element_core (
	input         			clock,
	input         			reset,
	// data signals
	output        			psum_in_ready,	
	input         			psum_in_valid,
	input 	signed 	[20:0] 	psum_in,
	input  			       	psum_out_ready,
	output 			       	psum_out_valid,
	output 	signed	[20:0] 	psum_out,
				
	input  			       	former_address_in_valid,
	input  			[7:0]  	former_address_in,
	input  			       	former_data_in_valid,
	input  			[12:0] 	former_data_in,
				
	input  			       	later_address_in_valid,
	input  			[6:0]  	later_address_in,
	input  			       	later_data_in_valid,
	input  			[11:0] 	later_data_in,
	
	// control signals
	input         			mac_en,
	input         			psum_enq_en,
	input         			load_en,
	output        			cal_fin,
	
	output 			       	former_address_write_fin,
	output 			       	former_data_write_fin,
				
	output 			       	later_address_write_fin,
	output 			       	later_data_write_fin,
				
	output 			       	psum_acc_fin,
	
	input			[4:0]	PSUM_DEPTH,
	input					psum_spad_clear
);

// ====================================================================	//
// 						 		Instantiation  							//
// ====================================================================	//
// PSumSPad module
wire					Psum_Spad_psum_in_ready; 
wire					Psum_Spad_psum_in_valid; 
wire	signed [20:0] 	Psum_Spad_psum_in; 
wire  					Psum_Spad_psum_out_ready; 
wire  					Psum_Spad_psum_out_valid; 
wire 	signed	[20:0] 	Psum_Spad_psum_out; 
wire 			[4:0] 	Psum_Spad_read_idx; 
wire 			[4:0] 	Psum_Spad_write_idx; 

// former address spad module
wire 			[7:0] 	former_address_spad_data_out;
wire 			 		former_address_spad_data_in_ready; 
wire 			 		former_address_spad_data_in_valid; 
wire 			[7:0] 	former_address_spad_data_in; 
wire 			 		former_address_spad_write_en; 
wire 			 		former_address_spad_write_fin;
wire 			 		former_address_spad_idx_inc;

// former data spad module
wire 			[7:0] 	former_data_spad_col_num; 
wire 			[12:0] 	former_data_spad_data_out;
wire 			 		former_data_spad_data_in_ready; 
wire 			 		former_data_spad_data_in_valid; 
wire 			[12:0] 	former_data_spad_data_in; 
wire 			 		former_data_spad_write_en; 
wire 			 		former_data_spad_write_fin;
wire 			 		former_data_spad_idx_inc;

// later address spad module
wire 			[6:0] 	later_address_spad_data_out; 
wire 			 		later_address_spad_data_in_ready;
wire 			 		later_address_spad_data_in_valid;
wire 			[6:0] 	later_address_spad_data_in; 
wire 			 		later_address_spad_write_en; 
wire 			 		later_address_spad_write_fin;
wire 			[4:0] 	later_address_spad_read_idx;
wire 			 		later_address_spad_idx_inc; 
wire 			 		later_address_spad_read_idx_en; 

// later data spad module
wire 			[6:0] 	later_data_spad_col_num;
wire 			[11:0] 	later_data_spad_data_out;
wire 			 		later_data_spad_data_in_ready; 
wire 			 		later_data_spad_data_in_valid; 
wire 			[11:0] 	later_data_spad_data_in; 
wire 			 		later_data_spad_write_en; 
wire 			 		later_data_spad_write_fin;
wire 			 		later_data_spad_read_en; 
wire 			[6:0] 	later_data_spad_read_idx; 
wire 			 		later_data_spad_read_idx_inc;
wire 			 		later_data_spad_read_idx_en;

Psum_Spad Psum_Spad_inst ( 
	.clock			(clock						),
	.reset			(reset						),
	.psum_in_ready	(Psum_Spad_psum_in_ready	),
	.psum_in_valid	(Psum_Spad_psum_in_valid	),
	.psum_in		(Psum_Spad_psum_in			),
	.psum_out_ready	(Psum_Spad_psum_out_ready	),
	.psum_out_vaild	(Psum_Spad_psum_out_valid	),
	.psum_out		(Psum_Spad_psum_out			),
	.read_idx		(Psum_Spad_read_idx			),
	.write_idx		(Psum_Spad_write_idx		),
	.psum_spad_clear(psum_spad_clear			)
);

Former_Address_Spad Former_Address_Spad_inst ( 
	.clock			(clock								),
	.reset			(reset								),
	.data_out		(former_address_spad_data_out		),
	.data_in_ready	(former_address_spad_data_in_ready	),
	.data_in_valid	(former_address_spad_data_in_valid	),
	.data_in		(former_address_spad_data_in		),
	.write_en		(former_address_spad_write_en		),
	.write_fin		(former_address_spad_write_fin		),
	.index_inc		(former_address_spad_idx_inc		)
);

Former_Data_Spad Former_Data_Spad_inst ( 
	.clock			(clock								),
	.reset			(reset								),
	.column_num		(former_data_spad_col_num			),
	.data_out		(former_data_spad_data_out			),
	.data_in_ready	(former_data_spad_data_in_ready		),
	.data_in_valid	(former_data_spad_data_in_valid		),
	.data_in		(former_data_spad_data_in			),
	.write_en		(former_data_spad_write_en			),
	.write_fin		(former_data_spad_write_fin			),
	.index_inc		(former_data_spad_idx_inc			)
);

Later_Address_Spad Later_Address_Spad_inst ( 
	.clock			(clock								),
	.reset			(reset								),
	.data_out		(later_address_spad_data_out		),
	.data_in_ready	(later_address_spad_data_in_ready	),
	.data_in_valid	(later_address_spad_data_in_valid	),
	.data_in		(later_address_spad_data_in			),
	.write_en		(later_address_spad_write_en		),
	.write_fin		(later_address_spad_write_fin		),
	.read_idx		(later_address_spad_read_idx		),
	.addr_read_inc	(later_address_spad_idx_inc			),
	.read_idx_en	(later_address_spad_read_idx_en		)
);

Later_Data_Spad Later_Data_Spad_inst (
	.clock			(clock							),
	.reset			(reset							),
	.column_num		(later_data_spad_col_num		),
	.data_out		(later_data_spad_data_out		),
	.data_in_ready	(later_data_spad_data_in_ready	),
	.data_in_valid	(later_data_spad_data_in_valid	),
	.data_in		(later_data_spad_data_in		),
	.write_en		(later_data_spad_write_en		),
	.write_fin		(later_data_spad_write_fin		),
	.read_en		(later_data_spad_read_en		),
	.read_idx		(later_data_spad_read_idx		),
	.index_inc		(later_data_spad_read_idx_inc	),
	.read_idx_en	(later_data_spad_read_idx_en	)
);

// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
parameter WEIGHT_MATRIX_ROW = 4;

// state parameters
localparam IDLE 				= 3'd0;			// the pad is idle, and if received mac_en signal from controller, then start 5 stage pipeline
localparam READ_FORMER_ADDRESS 	= 3'd1;			// read the former address
localparam READ_FORMER_DATA 	= 3'd2;			// read the former data
localparam READ_LATER_ADDRESS 	= 3'd3;			// read the later address
localparam READ_LATER_DATA_1 	= 3'd4;			// read the later data
localparam READ_LATER_DATA_2 	= 3'd5;			// wait one cycle as SRAM
localparam DO_MAC 				= 3'd6;			// wait for mac computation
localparam WRITE_BACK 			= 3'd7;			// write the partial sum back					


// ====================================================================	//
// 						 		Registers  								//
// ====================================================================	//
reg 		[2:0]	PE_state, next_PE_state;	// state FSM signals

reg 		[3:0] 	former_matrix_col_reg; 
reg 				former_matrix_inc_reg;
reg  				former_data_first_read_reg; 
reg 				later_data_first_read_reg; 

reg signed 	[20:0]	product_reg;    						// iact * weight                     							
reg signed 	[20:0] 	psum_load_reg;							// psum load from psum spad       
reg  				psum_load_state;						// determine psum accumulation is for psum spad or psum_in form PE ouside 
reg 		[4:0] 	psum_read_idx_reg, next_psum_read_idx;	// PSUM SPad read idx FSM signals


// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
// state FSM signals
wire IDLE_wire 					= PE_state == IDLE;
wire READ_FORMER_ADDRESS_wire 	= PE_state == READ_FORMER_ADDRESS;
wire READ_FORMER_DATA_wire 		= PE_state == READ_FORMER_DATA;
wire READ_LATER_ADDRESS_wire 	= PE_state == READ_LATER_ADDRESS;
wire READ_LATER_DATA_1_wire 	= PE_state == READ_LATER_DATA_1;
wire READ_LATER_DATA_2_wire 	= PE_state == READ_LATER_DATA_2;
wire DO_MAC_wire 				= PE_state == DO_MAC;			
wire WRITE_BACK_wire 			= PE_state == WRITE_BACK;		


// data coun vector decoding				       			
wire 		[4:0] 	former_matrix_row_wire	= former_data_spad_data_out	[4:0];
wire signed [7:0] 	former_matrix_data_wire	= former_data_spad_data_out	[12:5];
wire 		[3:0] 	later_matrix_row_wire	= later_data_spad_data_out	[3:0];  
wire signed [7:0] 	later_matrix_data_wire	= later_data_spad_data_out	[11:4];


// use the maximum value of the address to stand for current column is all zero to skip this column
wire former_zero_col_wire  					= former_address_spad_data_out 	== 8'd255;
wire later_zero_col_wire					= later_address_spad_data_out	== 7'd127;

wire read_later_zero_col_wire 				= former_matrix_row_wire == later_address_spad_data_out;
wire later_matrix_read_first_col_wire 		= former_matrix_row_wire == 5'd0; 


// SPad control
wire signed [20:0]	product_wire 			= (later_matrix_row_wire == 'd15) ? 'sd0 : (later_matrix_data_wire * former_matrix_data_wire);  // TODO 
wire signed [20:0] 	psum_load_wire 		 	= Psum_Spad_psum_out;
wire signed [20:0] 	psum_acc_result_wire 	= psum_load_state ? (psum_load_wire + psum_in) : (psum_load_reg + product_reg);
wire 		[4:0]  	psum_write_idx_wire  	= later_matrix_row_wire + (former_matrix_col_reg-1) * WEIGHT_MATRIX_ROW; 
wire				psum_read_fin_wire		= psum_read_idx_reg == PSUM_DEPTH;


wire former_data_spad_idx_inc_wire 			= former_address_spad_data_out == (former_data_spad_col_num + 'd1);
wire Iact_Data_Spad_read_fin_wire			= (former_matrix_data_wire == 'd0) & (~former_data_first_read_reg);
	
wire later_data_spad_read_fin_wire   		= (later_matrix_data_wire == 'd0); 
wire later_data_spad_idx_inc_wire   		= (later_address_spad_data_out == (later_data_spad_col_num + 'd1)) | later_data_spad_read_fin_wire;
wire later_address_spad_read_fin_wire 		= (later_address_spad_data_out == 'd0) ? 1'b1 : 1'b0;
	
wire Psum_Spad_read_valid_wire 				= psum_in_valid & psum_load_state;
wire Psum_Spad_read_idx_inc_wire 			= psum_out_ready & psum_out_valid;
wire Psum_Spad_read_fin_wire 				= (READ_FORMER_DATA_wire 	& Iact_Data_Spad_read_fin_wire)	|
											  (WRITE_BACK_wire 			& Iact_Data_Spad_read_fin_wire) | 
											  (psum_read_fin_wire 		& Psum_Spad_read_idx_inc_wire);


// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
// output signals
assign cal_fin 						= Iact_Data_Spad_read_fin_wire & ~IDLE_wire;
			
assign psum_in_ready 				= psum_out_ready & psum_load_state;
assign psum_out_valid 				= Psum_Spad_psum_out_ready & Psum_Spad_psum_out_valid & Psum_Spad_read_valid_wire;
assign psum_out 					= psum_acc_result_wire;
assign psum_acc_fin 				= Psum_Spad_read_fin_wire & psum_load_state;

assign former_address_write_fin		= former_address_spad_write_fin;
assign former_data_write_fin 		= former_data_spad_write_fin;
	
assign later_address_write_fin 		= later_address_spad_write_fin;
assign later_data_write_fin 		= later_data_spad_write_fin;


// instantiated module connection
assign Psum_Spad_psum_in_valid 				= WRITE_BACK_wire;
assign Psum_Spad_psum_in 					= WRITE_BACK_wire ? psum_acc_result_wire : 21'sd0;
assign Psum_Spad_psum_out_ready 			= DO_MAC_wire | Psum_Spad_read_valid_wire;
assign Psum_Spad_read_idx 					= next_psum_read_idx;
assign Psum_Spad_write_idx 					= psum_write_idx_wire;

assign former_address_spad_data_in_valid	= former_address_in_valid;
assign former_address_spad_data_in 			= former_address_in;
assign former_address_spad_write_en 		= load_en;
assign former_address_spad_idx_inc 			= (READ_FORMER_ADDRESS_wire && former_zero_col_wire) 												|| 
											  (READ_LATER_ADDRESS_wire 	&& former_data_spad_idx_inc_wire	&& later_zero_col_wire) 			|| 
											  (WRITE_BACK_wire 			&& former_data_spad_idx_inc_wire	&& later_data_spad_idx_inc_wire) 	|| 
											  (~IDLE_wire 				&& cal_fin);

assign former_data_spad_data_in_valid 		= former_data_in_valid;
assign former_data_spad_data_in 			= former_data_in;
assign former_data_spad_write_en 			= load_en;	
assign former_data_spad_idx_inc 			= (READ_FORMER_ADDRESS_wire && (~former_zero_col_wire | ~former_data_spad_idx_inc_wire) && (~former_data_first_read_reg)) 	|| 
											  (READ_LATER_ADDRESS_wire 	&& later_zero_col_wire && (~former_data_spad_idx_inc_wire)) 									|| 
											  (WRITE_BACK_wire 			&& later_data_spad_idx_inc_wire && (~former_data_spad_idx_inc_wire)) 							|| 
											  (~IDLE_wire 				&& Iact_Data_Spad_read_fin_wire);

assign later_address_spad_data_in_valid		= later_address_in_valid;
assign later_address_spad_data_in 			= later_address_in;
assign later_address_spad_write_en 			= load_en;
assign later_address_spad_read_idx 			= (READ_FORMER_DATA_wire & later_data_first_read_reg 	& (~later_matrix_read_first_col_wire)) ? (former_matrix_row_wire - 4'd1) : former_matrix_row_wire;
assign later_address_spad_read_idx_en 		= (READ_FORMER_DATA_wire 	| READ_LATER_ADDRESS_wire) 	& later_data_first_read_reg;
assign later_address_spad_idx_inc 			= (READ_LATER_DATA_1_wire 	| DO_MAC_wire) 				& later_zero_col_wire;

assign later_data_spad_data_in_valid 		= later_data_in_valid;
assign later_data_spad_data_in 				= later_data_in;
assign later_data_spad_write_en 			= load_en;
assign later_data_spad_read_en 				= READ_LATER_DATA_1_wire;
assign later_data_spad_read_idx 			= later_matrix_read_first_col_wire ? 'd0 : later_address_spad_data_out;
assign later_data_spad_read_idx_en 			= (READ_LATER_ADDRESS_wire) & later_data_first_read_reg 	& (~later_zero_col_wire);
assign later_data_spad_read_idx_inc 		= (READ_LATER_ADDRESS_wire 	& (~later_zero_col_wire) 		& (~later_data_first_read_reg)) | 
											  (WRITE_BACK_wire 			& (~later_data_spad_idx_inc_wire));

// state converted signals
wire former_address_read_done_wire	= ~(former_data_spad_idx_inc_wire & former_zero_col_wire);
wire former_data_read_done_wire 	= Iact_Data_Spad_read_fin_wire;
wire later_data_read_done 			= later_data_spad_idx_inc_wire 	| later_address_spad_read_fin_wire;
wire former_one_col_read_done		= former_data_spad_idx_inc_wire | later_address_spad_read_fin_wire;

// next state logic
always@(*) begin
	case(PE_state)
		IDLE 				: next_PE_state = mac_en 						? READ_FORMER_ADDRESS 	: IDLE;
		READ_FORMER_ADDRESS : next_PE_state = former_address_read_done_wire ? READ_FORMER_DATA 		: READ_FORMER_ADDRESS;
		READ_FORMER_DATA 	: next_PE_state = former_data_read_done_wire 	? IDLE 					: READ_LATER_ADDRESS;
		READ_LATER_ADDRESS 	: next_PE_state = ~later_zero_col_wire 			? READ_LATER_DATA_1 	: 
											  former_data_spad_idx_inc_wire ? READ_FORMER_ADDRESS 	: READ_FORMER_DATA;
		READ_LATER_DATA_1 	: next_PE_state = READ_LATER_DATA_2;
		READ_LATER_DATA_2 	: next_PE_state = DO_MAC;
		DO_MAC 				: next_PE_state = WRITE_BACK;
		WRITE_BACK 	        : next_PE_state = former_data_read_done_wire 	? IDLE 					: 
											  ~later_data_read_done 		? READ_LATER_DATA_1 	: 
											  former_one_col_read_done 		? READ_FORMER_ADDRESS 	: READ_FORMER_DATA;
		default				: next_PE_state = IDLE;
	endcase
end


// ====================================================================	//
// 						 		Sequential  							//
// ====================================================================	//
// FSM
always@(posedge clock) begin
	if(reset) begin
		PE_state <= IDLE;
	end
	else begin
		PE_state <= next_PE_state;
	end
end	

always@(posedge clock) begin
	if(reset) begin
		former_matrix_inc_reg <= 1'b0;
	end
	else if(READ_FORMER_ADDRESS_wire)begin
		former_matrix_inc_reg <= former_zero_col_wire;
	end
end


always@(posedge clock) begin
	if(reset) begin
		former_matrix_col_reg <= 'd0;
	end
	else if(psum_enq_en)begin
		former_matrix_col_reg <= 'd0;
	end
	else if(READ_FORMER_ADDRESS_wire)begin
		former_matrix_col_reg <= former_matrix_col_reg + former_matrix_inc_reg + 'd1;
	end
end

always@(posedge clock) begin
	if(reset) begin
		former_data_first_read_reg <= 1'b1;
	end 
	else begin
		if(READ_FORMER_DATA_wire | WRITE_BACK_wire) begin
			former_data_first_read_reg <= Iact_Data_Spad_read_fin_wire | former_data_first_read_reg;
		end
		else if(READ_LATER_ADDRESS_wire) begin
			former_data_first_read_reg <= 1'b0;
		end
	end
end	
	
always@(posedge clock) begin
	if(reset) begin
		later_data_first_read_reg <= 1'b1;
	end 
	else begin
	    if(IDLE_wire) begin
			later_data_first_read_reg <= mac_en | later_data_first_read_reg;
		end
		else if(READ_LATER_ADDRESS_wire) begin
			later_data_first_read_reg <= later_zero_col_wire | later_data_first_read_reg;
		end
		else if(WRITE_BACK_wire && !Iact_Data_Spad_read_fin_wire) begin
			later_data_first_read_reg <= later_data_spad_idx_inc_wire | later_address_spad_read_fin_wire;
		end
	end
end

always@(posedge clock) begin	
	if(reset) begin
		product_reg <= 21'sd0;
	end 
	else begin
		if(DO_MAC_wire) begin
			product_reg <= product_wire;	// TODO
		end
	end
end

always@(posedge clock) begin
	if(reset) begin
		psum_load_reg <= 21'sd0;
	end 
	else begin
		psum_load_reg <= psum_load_wire;
	end
end

always@(posedge clock) begin
	if(reset) begin
		psum_load_state <= 1'b0; 
	end 
	else if(psum_acc_fin) begin
		psum_load_state <= 1'b0;
	end 
	else begin
		psum_load_state <= psum_enq_en | psum_load_state;
	end
end
	
	
// psum read index FSM
always@(posedge clock) begin	
	if(reset) begin 
		psum_read_idx_reg <= 5'd0; 
	end 
	else begin 
		psum_read_idx_reg <= next_psum_read_idx;
	end 
end

// next psum read index logic
always@(*) begin	
	if(READ_LATER_DATA_2_wire) begin 
		next_psum_read_idx <= Psum_Spad_write_idx;
	end 
	else if (Psum_Spad_read_fin_wire) begin 
		next_psum_read_idx <= 5'd0;
	end 
	else if (Psum_Spad_read_idx_inc_wire) begin 
		next_psum_read_idx <= psum_read_idx_reg + 5'd1;
	end
	else begin
		next_psum_read_idx <= psum_read_idx_reg;
	end
end


endmodule

// ===== repo/FPGA_design/src/PE_Cluster/PE/Processing_Element.v =====
// ====================================================================================================== //
// This module is the Top-level of PE.
// PE module contains the FIFOs of all data types and the core PE_Pad.
// The only control signals write_fin used to control the data in from uppper level module, 
// which is used to determine whether the data should be reuse.
// ====================================================================================================== //


module ProcessingElement (
	input         			clock,
	input         			reset,
	// data signals
	output        			psum_in_ready,
	input         			psum_in_valid,
	input 	signed 	[20:0] 	psum_in,
	input         			psum_out_ready,
	output        			psum_out_valid,
	output 	signed 	[20:0] 	psum_out,
	
	input         			iact_address_in_valid,
	input  			[7:0]  	iact_address_in,
	input  			       	iact_data_in_valid,
	input  			[12:0] 	iact_data_in,
				
	input  			       	weight_address_in_valid,
	input  			[6:0]  	weight_address_in,
	input  			       	weight_data_in_valid,
	input  			[11:0] 	weight_data_in,
	
	// control signals
	output 			       	iact_address_write_fin,
	output 			       	iact_data_write_fin,
	output 			       	psum_add_fin,
				
	input  			       	psum_enq_en,
	input  			       	do_load_en,
	output 			       	cal_fin,
			
	input					iact_write_fin_clear,
	input					weight_write_fin_clear,
	output 					all_write_fin,
	
	input			[4:0]	PSUM_DEPTH,
	input					psum_spad_clear
);

// ====================================================================	//
// 						 		Instantiation  							//
// ====================================================================	//
// PE ctrl module
wire  				PE_ctrl_do_mac_en; 
wire  				PE_ctrl_fromTop_psum_enq_en; 
wire  				PE_ctrl_fromTop_do_load_en; 
wire  				PE_ctrl_fromTop_cal_fin; 
wire  				PE_ctrl_Top_psum_enq_en; 
wire  				PE_ctrl_Top_do_load_en; 
wire  				PE_ctrl_Top_cal_fin; 
wire  				PE_ctrl_Top_write_fin; 

// PE pad module
wire  				PE_pad_do_mac_en; 
wire  				PE_pad_psum_enq_en; 
wire  				PE_pad_do_load_en; 
wire  				PE_pad_cal_fin; 
wire  				PE_pad_psum_in_ready; 
wire  				PE_pad_psum_in_valid; 
wire signed [20:0] 	PE_pad_psum_in; 
wire  				PE_pad_psum_out_ready; 
wire  				PE_pad_psum_out_valid; 
wire signed [20:0] 	PE_pad_psum_out; 
wire		 		PE_pad_former_address_in_valid; 
wire		[7:0] 	PE_pad_former_address_in; 
wire		 		PE_pad_former_data_in_valid; 
wire		[12:0] 	PE_pad_former_data_in; 
wire		 		PE_pad_later_address_in_valid; 
wire		[6:0] 	PE_pad_later_address_in; 
wire		 		PE_pad_later_data_in_valid; 
wire		[11:0] 	PE_pad_later_data_in;
wire		 		PE_pad_former_address_write_fin; 
wire		 		PE_pad_former_data_write_fin; 
wire		 		PE_pad_later_address_write_fin; 
wire		 		PE_pad_later_data_write_fin; 
wire		 		PE_pad_psum_add_fin; 

// FIFO
wire 				FIFO_former_address_in_ready; 
wire 				FIFO_former_address_in_valid; 
wire 		[7:0] 	FIFO_former_address_in; 
wire 		 		FIFO_former_address_out_valid; 
wire 		[7:0] 	FIFO_former_address_out; 
		
wire 		 		FIFO_former_data_in_ready; 
wire 		 		FIFO_former_data_in_valid; 
wire 		[12:0] 	FIFO_former_data_in;
wire 		 		FIFO_former_data_out_valid; 
wire 		[12:0] 	FIFO_former_data_out;
		
wire 		 		FIFO_later_address_in_ready; 
wire 		 		FIFO_later_address_in_valid; 
wire 		[6:0] 	FIFO_later_address_in; 
wire 		 		FIFO_later_address_out_valid; 
wire 		[6:0] 	FIFO_later_address_out; 
		
wire 		 		FIFO_later_data_in_ready; 
wire 		 		FIFO_later_data_in_valid; 
wire 		[11:0] 	FIFO_later_data_in;
wire 		 		FIFO_later_data_out_valid; 
wire 		[11:0] 	FIFO_later_data_out;

wire  				FIFO_in_psum_in_ready; 
wire  				FIFO_in_psum_in_valid; 
wire signed [20:0] 	FIFO_in_psum_in; 
wire  				FIFO_in_psum_out_ready; 
wire  				FIFO_in_psum_out_valid; 
wire signed [20:0] 	FIFO_in_psum_out; 

wire  				FIFO_out_psum_in_ready; 
wire  				FIFO_out_psum_in_valid; 
wire signed [20:0] 	FIFO_out_psum_in;
wire  				FIFO_out_psum_out_ready; 
wire  				FIFO_out_psum_out_valid; 
wire signed [20:0] 	FIFO_out_psum_out;


Processing_Element_Controller Processing_Element_Controller_inst ( 
	.clock					(clock						),
	.reset					(reset						),
	.mac_en					(PE_ctrl_do_mac_en			),
	.from_top_psum_enq_en	(PE_ctrl_fromTop_psum_enq_en),  
	.from_top_do_load_en	(PE_ctrl_fromTop_do_load_en	),    
	.from_top_cal_fin		(PE_ctrl_fromTop_cal_fin	),          
	.top_psum_enq_en		(PE_ctrl_Top_psum_enq_en	),          
	.top_do_load_en			(PE_ctrl_Top_do_load_en		),            
	.top_cal_fin			(PE_ctrl_Top_cal_fin		),                  
	.top_write_fin			(PE_ctrl_Top_write_fin		)
);

Processing_Element_core Processing_Element_core_inst (
	.clock						(clock),                                           
	.reset						(reset							),                                           
	.mac_en						(PE_pad_do_mac_en				),                            
	.psum_enq_en				(PE_pad_psum_enq_en				),                        
	.load_en					(PE_pad_do_load_en				),                             
	.cal_fin					(PE_pad_cal_fin					),                                
	.psum_in_ready				(PE_pad_psum_in_ready			),                    
	.psum_in_valid				(PE_pad_psum_in_valid			),                    
	.psum_in					(PE_pad_psum_in					),                                
	.psum_out_ready				(PE_pad_psum_out_ready			),                  
	.psum_out_valid				(PE_pad_psum_out_valid			),                  
	.psum_out					(PE_pad_psum_out				),                              
	.former_address_in_valid	(PE_pad_former_address_in_valid	), 
	.former_address_in			(PE_pad_former_address_in		),             
	.former_data_in_valid		(PE_pad_former_data_in_valid	),       
	.former_data_in				(PE_pad_former_data_in			),                   
	.later_address_in_valid		(PE_pad_later_address_in_valid	),      
	.later_address_in			(PE_pad_later_address_in		),           
	.later_data_in_valid		(PE_pad_later_data_in_valid		),     
	.later_data_in				(PE_pad_later_data_in			),
	.former_address_write_fin	(PE_pad_former_address_write_fin), 
	.former_data_write_fin		(PE_pad_former_data_write_fin	),       
	.later_address_write_fin	(PE_pad_later_address_write_fin	),            
	.later_data_write_fin		(PE_pad_later_data_write_fin	),              
	.psum_acc_fin				(PE_pad_psum_add_fin			),
	.PSUM_DEPTH					(PSUM_DEPTH						),
	.psum_spad_clear			(psum_spad_clear				)
);                                                                                  
              

// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
parameter FORMER_ADDR_DATA_WIDTH 	= 8;	// fomer matrix contains 256 elements (8-bit)
parameter FORMER_DATA_DATA_WIDTH 	= 13;	// data bitwidth = 8, count birwidth = 5
parameter LATER_ADDR_DATA_WIDTH 	= 7;	// later matrix contains 128 elements (7-bit)
parameter LATER_DATA_DATA_WIDTH 	= 12;	// data bitwidth = 8, count birwidth = 4
  
// FIFO for former address                                                          
PE_data_FIFO #(
	.DATA_IN_WIDTH (FORMER_ADDR_DATA_WIDTH)
	)
former_addr_FIFO (                          
  .clock			(clock							),                                                                  
  .reset			(reset							),                                                                  
  .data_in_ready	(FIFO_former_address_in_ready	),      
  .data_in_valid	(FIFO_former_address_in_valid	),      
  .data_in			(FIFO_former_address_in			),             
  .data_out_valid	(FIFO_former_address_out_valid	),     
  .data_out			(FIFO_former_address_out		)             
);                                             

// FIFO for former data 
PE_data_FIFO #(
	.DATA_IN_WIDTH(FORMER_DATA_DATA_WIDTH)
	)
former_data_FIFO (
  .clock			(clock						),
  .reset			(reset						),
  .data_in_ready	(FIFO_former_data_in_ready	),
  .data_in_valid	(FIFO_former_data_in_valid	),
  .data_in			(FIFO_former_data_in		),
  .data_out_valid	(FIFO_former_data_out_valid	),
  .data_out			(FIFO_former_data_out		)
);

// FIFO for later address 
PE_data_FIFO #(
	.DATA_IN_WIDTH(LATER_ADDR_DATA_WIDTH)
	)
later_addr_FIFO ( 
  .clock			(clock							),
  .reset			(reset							),
  .data_in_ready	(FIFO_later_address_in_ready	),
  .data_in_valid	(FIFO_later_address_in_valid	),
  .data_in			(FIFO_later_address_in			),
  .data_out_valid	(FIFO_later_address_out_valid	),
  .data_out			(FIFO_later_address_out			)
);

// FIFO for later data 
PE_data_FIFO #(
	.DATA_IN_WIDTH(LATER_DATA_DATA_WIDTH)
	)
later_data_FIFO ( 
  .clock			(clock						),
  .reset			(reset						),
  .data_in_ready	(FIFO_later_data_in_ready	),
  .data_in_valid	(FIFO_later_data_in_valid	),
  .data_in			(FIFO_later_data_in			),
  .data_out_valid	(FIFO_later_data_out_valid	),
  .data_out			(FIFO_later_data_out		)
);

// FIFO for psum in
PE_psum_FIFO psum_in_FIFO ( 
  .clock			(clock					),                                
  .reset			(reset					),                                
  .data_in_ready	(FIFO_in_psum_in_ready	),            
  .data_in_valid	(FIFO_in_psum_in_valid	),            
  .data_in			(FIFO_in_psum_in		),                      
  .data_out_ready	(FIFO_in_psum_out_ready	),              
  .data_out_valid	(FIFO_in_psum_out_valid	),              
  .data_out			(FIFO_in_psum_out		)                      
);                                                      

// FIFO for psum out
PE_psum_FIFO psum_out_FIFO ( 
  .clock			(clock					),
  .reset			(reset					),
  .data_in_ready	(FIFO_out_psum_in_ready	),
  .data_in_valid	(FIFO_out_psum_in_valid	),
  .data_in			(FIFO_out_psum_in		),
  .data_out_ready	(FIFO_out_psum_out_ready),
  .data_out_valid	(FIFO_out_psum_out_valid),
  .data_out			(FIFO_out_psum_out		)
);


// ====================================================================	//
// 						 		Registers  								//
// ====================================================================	//
reg  former_addr_write_fin_reg; 
reg  former_data_write_fin_reg; 
reg  later_addr_write_fin_reg; 
reg  later_data_write_fin_reg; 


// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
// output wire connection
assign all_write_fin 					= former_addr_write_fin_reg & former_data_write_fin_reg & later_addr_write_fin_reg & later_data_write_fin_reg;
assign psum_in_ready 					= FIFO_in_psum_in_ready;
assign psum_out_valid 					= FIFO_out_psum_out_valid;
assign psum_out 						= FIFO_out_psum_out;
assign iact_address_write_fin 			= PE_pad_former_address_write_fin;
assign iact_data_write_fin 				= PE_pad_former_data_write_fin;
assign psum_add_fin 					= PE_pad_psum_add_fin;
assign cal_fin 							= PE_ctrl_Top_cal_fin;

// instantiated module connection
assign PE_ctrl_fromTop_cal_fin 			= PE_pad_cal_fin;
assign PE_ctrl_Top_psum_enq_en 			= psum_enq_en;
assign PE_ctrl_Top_do_load_en 			= do_load_en;
assign PE_ctrl_Top_write_fin 			= former_addr_write_fin_reg & former_data_write_fin_reg & later_addr_write_fin_reg & later_data_write_fin_reg;

assign PE_pad_do_mac_en 				= PE_ctrl_do_mac_en;
assign PE_pad_psum_enq_en 				= PE_ctrl_fromTop_psum_enq_en;
assign PE_pad_do_load_en 				= PE_ctrl_fromTop_do_load_en;
assign PE_pad_psum_in_valid 			= FIFO_in_psum_out_valid;
assign PE_pad_psum_in 					= FIFO_in_psum_out;
assign PE_pad_psum_out_ready 			= FIFO_out_psum_in_ready;
assign PE_pad_former_address_in_valid 	= FIFO_former_address_out_valid;
assign PE_pad_former_address_in 		= FIFO_former_address_out;
assign PE_pad_former_data_in_valid 		= FIFO_former_data_out_valid;
assign PE_pad_former_data_in 			= FIFO_former_data_out;
assign PE_pad_later_address_in_valid 	= FIFO_later_address_out_valid;
assign PE_pad_later_address_in 			= FIFO_later_address_out;
assign PE_pad_later_data_in_valid 		= FIFO_later_data_out_valid;
assign PE_pad_later_data_in 			= FIFO_later_data_out;

assign FIFO_former_address_in_valid 	= iact_address_in_valid;
assign FIFO_former_address_in 			= iact_address_in;
assign FIFO_former_data_in_valid 		= iact_data_in_valid;
assign FIFO_former_data_in 				= iact_data_in;
	
assign FIFO_later_address_in_valid 		= weight_address_in_valid;
assign FIFO_later_address_in 			= weight_address_in;
assign FIFO_later_data_in_valid 		= weight_data_in_valid;
assign FIFO_later_data_in 				= weight_data_in;

assign FIFO_in_psum_in_valid 			= psum_in_valid;
assign FIFO_in_psum_in 					= psum_in;
assign FIFO_in_psum_out_ready 			= PE_pad_psum_in_ready;
		
assign FIFO_out_psum_in_valid 			= PE_pad_psum_out_valid;
assign FIFO_out_psum_in 				= PE_pad_psum_out;
assign FIFO_out_psum_out_ready 			= psum_out_ready;


// ====================================================================	//
// 						 		Sequential  							//
// ====================================================================	//
always@(posedge clock) begin
	if (reset) begin 
		former_addr_write_fin_reg <= 1'b0; 
		former_data_write_fin_reg <= 1'b0; 
	end 
	else if (iact_write_fin_clear) begin 
		former_addr_write_fin_reg <= 1'b0;
		former_data_write_fin_reg <= 1'b0;
	end 
	else begin
		former_addr_write_fin_reg <= PE_pad_former_address_write_fin | former_addr_write_fin_reg;
		former_data_write_fin_reg <= PE_pad_former_data_write_fin 	 | former_data_write_fin_reg;
	end
end

	
always@(posedge clock) begin	
	if (reset) begin 
		later_addr_write_fin_reg <= 1'b0; 
		later_data_write_fin_reg <= 1'b0; 
	end 
	else if (all_write_fin & weight_write_fin_clear) begin 
		later_addr_write_fin_reg <= 1'b0;
		later_data_write_fin_reg <= 1'b0;
	end 
	else begin
		later_addr_write_fin_reg <= PE_pad_later_address_write_fin	| later_addr_write_fin_reg;
		later_data_write_fin_reg <= PE_pad_later_data_write_fin 	| later_data_write_fin_reg;
	end
end


endmodule

// ===== repo/FPGA_design/src/PE_Cluster/PE/SPad/Former_addr_Spad.v =====
// ====================================================================================================== //
// This module is the former address spad.
// Former address spad is used to store the address vector by CSC decoder, whose range is 0~255.
// For convolution layer, Former address spad stores the weight address.
// For depthwise-convolution and fully conncected layer, Former address spad stores the iact address.
// For one former matrix, the number of address is the width of the matrix plus one (for zero end sign).
// ====================================================================================================== //

module Former_Address_Spad(
	input        		clock,
	input        		reset,
	// data signals
	output       		data_in_ready,
	input        		data_in_valid,
	input  		[7:0] 	data_in,
	output 	 	[7:0] 	data_out,		// 8b : Can store 2^8=256 data at most
	// control signals
	input        		write_en,
	output       		write_fin,
	input       		index_inc 		// combine read_en and index increase
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam SPAD_DEPTH = 12;
localparam SPAD_WIDTH = 8;

// ================================================	//
// 					 Registers  					//
// ================================================	//
reg [SPAD_WIDTH-1:0] 	Iact_Address_Spad [0:SPAD_DEPTH-1]; // TODO : use register file IP
reg [3:0] 				data_write_addr;
reg [3:0] 				data_read_addr; 

// ================================================	//
// 					 	Wires  						//
// ================================================	//
wire  data_in_shake		= data_in_ready & data_in_valid & write_en; 
wire  read_fin 			= (data_out == 'd0) & index_inc; 

// ================================================	//
// 					 Combination  					//
// ================================================	//
assign write_fin 		= (data_in == 'd0) & data_in_shake; 
assign data_in_ready 	= 1'b1; 
assign data_out 	 	= Iact_Address_Spad[data_read_addr]; 

// ================================================	//
// 					 Sequential  					//
// ================================================	//
// write spad
integer i;
always@(posedge clock) begin
	if(reset) begin
		for(i=0; i<SPAD_DEPTH; i=i+1) begin
			Iact_Address_Spad[i] <= 'd0;
		end
	end
	else if(data_in_shake) begin
		Iact_Address_Spad[data_write_addr] <= data_in;
	end
end

// write addr
always@(posedge clock) begin
	if(reset) begin 
		data_write_addr <= 'd0; 
	end 
	else if(data_in_shake) begin 
		if(write_fin) begin 
			data_write_addr <= 'd0;
		end 
		else begin
			data_write_addr <= data_write_addr + 'd1;
		end
	end
end

// read addr
always@(posedge clock) begin  
	if(reset) begin
		data_read_addr <= 'd0; 
	end 
	else if(index_inc) begin 
		if(read_fin) begin 
			data_read_addr <= 'd0; 
		end 
		else begin
			data_read_addr <= data_read_addr + 'd1; 
		end
	end
end


endmodule

// ===== repo/FPGA_design/src/PE_Cluster/PE/SPad/Former_data_Spad.v =====
// ====================================================================================================== //
// This module is the former data spad.
// Former data spad is used to store the data vector and count vector by CSC decoder, whose range is -128~127(INT-8).
// 
// For convolution layer, Former data spad stores the weight data.
// For depthwise-convolution and fully conncected layer, Former data spad stores the iact data.
// 
// The count bitwidth is 5, the data bitwidth is 8.
// The count bitwidth = 5 represents the row of former matrix can be 32 at most.
// 
// For FPGA implementation, former data spad uses BRAM to store data.
// ====================================================================================================== //


module Former_Data_Spad(
	input         		clock,
	input         		reset,
	// data signals
	output        		data_in_ready,
	input         		data_in_valid,
	input  		[12:0] 	data_in,
	output 		[12:0] 	data_out,		// 8b for data, 5b for count, there are 2^5=32 columns in this Spad at most
	output 		[7:0]  	column_num,		// use the count to determine which column of later matrix should be read
	// control signals
	input        		write_en,
	output        		write_fin,
	input         		index_inc 		// combine read_en and index increase
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam SPAD_DEPTH = 200;
localparam SPAD_WIDTH = 13;


// ================================================	//
// 					 Registers  					//
// ================================================	//
reg [7:0] spad_write_addr;
reg [7:0] spad_read_addr; 


// ================================================	//
// 					 	Wires  						//
// ================================================	//
wire  data_in_shake = data_in_ready & data_in_valid & write_en; 
wire  read_fin 	 	= (data_out == 'd0) & index_inc; 

// RAM read delay 1 cycle for BRAM
wire [7:0] next_data_read_addr = index_inc ? (read_fin ? 'd0 : (spad_read_addr + 'd1)) : spad_read_addr;


// ================================================	//
// 					 Combination  					//
// ================================================	//
assign write_fin 	= (data_in  == 'd0) & data_in_shake; 
assign data_in_ready= 1'b1; 
assign column_num 	= spad_read_addr; 
// assign data_out 	 = Iact_Data_Spad[spad_read_addr]; 


// ================================================	//
// 					 Sequential  					//
// ================================================	//
// write addr
always @(posedge clock) begin
	if (reset) begin
		spad_write_addr <= 'd0;
	end 
	else if (data_in_shake) begin 
		if (write_fin) begin 
			spad_write_addr <= 'd0;
		end 
		else begin
			spad_write_addr <= spad_write_addr + 'd1; 
		end
	end
end

// read addr
always @(posedge clock) begin
	if (reset) begin 
		spad_read_addr <= 'd0; 
	end 
	else begin 
		spad_read_addr <= next_data_read_addr;
	end
end



// ====================================================	//
// 						 BRAM IP	  					//
// ====================================================	//
wire 			IP_BRAM_write_en	= data_in_shake;
wire			IP_BRAM_read_en		= 'd1;
wire 	[7:0]	IP_BRAM_write_addr	= spad_write_addr;
wire 	[7:0]	IP_BRAM_read_addr	= next_data_read_addr;
wire	[12:0]	IP_BRAM_data_in		= data_in;
wire	[12:0]	IP_BRAM_data_out;

assign data_out	= IP_BRAM_data_out;
	
Iact_DATA_Spad_BRAM Iact_DATA_Spad_BRAM_inst (
    .clk			(clock					),
	.reset			(reset					),
	.write_en       (IP_BRAM_write_en       ),
	.read_en        (IP_BRAM_read_en        ),
	.write_addr     (IP_BRAM_write_addr     ),
	.read_addr      (IP_BRAM_read_addr      ),
	.data_in        (IP_BRAM_data_in        ),
	.data_out       (IP_BRAM_data_out       )
);

endmodule


module Iact_DATA_Spad_BRAM(
    input 			clk,
	input			reset,
	input 			write_en,
	input			read_en,
	
	input 	[7:0]	write_addr,
	input 	[7:0]	read_addr,
	
	input	[12:0]	data_in,
	
	output	[12:0]	data_out
);

wire		wr;
wire [7:0] 	addra;
wire [12:0] dina;
wire [12:0] douta;

IP_Iact_DATA_Spad_BRAM u0 (   	
  .clka		(clk	),    	
  .rsta		(reset	),
  .wea		(wr		),      	
  .addra	(addra	),  	
  .dina		(dina	),    	
  .douta	(douta	)  	
);

// need 200 cycles to clear spad data
reg	[6:0]	clear_count;
reg 		clear_flag;
always @(posedge clk) begin
	if (reset) begin
		clear_flag <= 'd1; 
	end
	else if(clear_count == 'd99) begin
		clear_flag <= 'd0; 
	end
end

always @(posedge clk) begin
	if (reset) begin
		clear_count <= 'd0; 
	end
	else if(clear_flag) begin
		clear_count <= (clear_count == 'd99) ? 'd0 : (clear_count + 'd1); 
	end
end


assign wr		= write_en | clear_flag;
assign addra 	= write_en ? write_addr	: (clear_flag ? clear_count : read_addr);
assign dina 	= write_en ? data_in 	: 'd0;

assign data_out = ~write_en	? douta		: 'd0;


endmodule

// ===== repo/FPGA_design/src/PE_Cluster/PE/SPad/Later_addr_Spad.v =====
// ====================================================================================================== //
// This module is the later address spad.
// later address spad is used to store the address vector by CSC decoder, whose range is 0~127.
// For convolution layer, later address spad stores the iact address.
// For depthwise-convolution and fully conncected layer, later address spad stores the weight address.
// For one later matrix, the number of address is the width of the matrix plus one (for zero end sign).
// ====================================================================================================== //


module Later_Address_Spad(
	input        		clock,
	input        		reset,
	// data signals
	output       		data_in_ready,
	input        		data_in_valid,
	input  		[6:0] 	data_in,
	output 		[6:0]	data_out,			// 7b : Can store 2^7=128 data at most 
	// control signals
	input        		write_en,
	output       		write_fin,
	input  		[4:0] 	read_idx,
	input        		read_idx_en,
	input        		addr_read_inc
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam SPAD_DEPTH = 32;
localparam SPAD_WIDTH = 7;


// ================================================	//
// 					 Registers  					//
// ================================================	//
reg [SPAD_WIDTH-1:0] 	Weight_Address_Spad [0:SPAD_DEPTH-1]; // TODO : use register file IP
reg [4:0] 				spad_write_addr;
reg [4:0] 				spad_read_addr;


// ================================================	//
// 					 	Wires  						//
// ================================================	//
wire  data_in_shake = data_in_ready & data_in_valid & write_en;
wire  read_fin   	= (data_out == 'd0) & addr_read_inc;


// ================================================	//
// 					 Combination  					//
// ================================================	//
assign write_fin 		= (data_in == 'd0) & data_in_shake;
assign data_in_ready	= 1'd1;
assign data_out  		= Weight_Address_Spad[spad_read_addr];


// ================================================	//
// 					 Sequential  					//
// ================================================	//
// write spad
integer i;
always @(posedge clock) begin
	if (reset) begin
		for(i=0; i<SPAD_DEPTH; i=i+1) begin
			Weight_Address_Spad[i] <= 7'd127;
		end
	end
	else if(data_in_shake) begin
		Weight_Address_Spad[spad_write_addr] <= data_in;
	end
end

// write addr
always @(posedge clock) begin
    if (reset) begin
		spad_write_addr <= 'd0;
    end 
	else if (data_in_shake) begin
		if (write_fin) begin
			spad_write_addr <= 'd0;
		end 
		else begin
			spad_write_addr <= spad_write_addr + 'd1;
		end
    end
end

// read addr
always @(posedge clock) begin	
    if (reset) begin
		spad_read_addr <= 'd0;
    end 
	else if (read_idx_en) begin
		spad_read_addr <= read_idx;
    end 
	else if (addr_read_inc) begin
		if (read_fin) begin
			spad_read_addr <= 'd0;
		end 
		else begin
			spad_read_addr <= spad_read_addr + 'd1;
		end
    end
end

  
endmodule

// ===== repo/FPGA_design/src/PE_Cluster/PE/SPad/Later_data_Spad.v =====
// ====================================================================================================== //
// This module is the later data spad.
// later data spad is used to store the data vector and count vector by CSC decoder, whose range is -128~127(INT-8).
// 
// For convolution layer, later data spad stores the iact data.
// For depthwise-convolution and fully conncected layer, later data spad stores the weight data.
// 
// The count bitwidth is 4, the data bitwidth is 8.
// The count bitwidth = 4 represents the row of later matrix can be 16 at most.
// 
// For FPGA implementation, later data spad uses BRAM to store data.
// ====================================================================================================== //


module Later_Data_Spad(
	input         		clock,
	input         		reset,
	// data signals
	output        		data_in_ready,
	input         		data_in_valid,
	input  		[11:0] 	data_in,
	output 		[11:0] 	data_out,		// 8b for data, 4b for count, there are 2^4 rows in a Spad at most.
	output reg 	[6:0]  	column_num,		// use the count to determine whether the later data read done.
	// control signals
	input         		write_en,
	output        		write_fin,
	input         		read_en,
	input  		[6:0]  	read_idx,
	input         		index_inc,
	input         		read_idx_en
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam SPAD_DEPTH = 100;
localparam SPAD_WIDTH = 12;


// ================================================	//
// 					 Registers  					//
// ================================================	//
reg [6:0] spad_write_addr;
reg [6:0] spad_read_addr;


// ================================================	//
// 					 	Wires  						//
// ================================================	//
wire  data_in_shake = data_in_ready & data_in_valid & write_en;
wire  read_fin   	= (data_out == 'd0) & index_inc;

// RAM read delay 1 cycle for BRAM
wire [6:0] next_data_read_addr = read_en ? column_num : spad_read_addr;


// ================================================	//
// 					 Combination  					//
// ================================================	//
assign write_fin 		= (data_in == 'd0) & data_in_shake;
assign data_in_ready 	= 1'd1;


// ================================================	//
// 					 Sequential  					//
// ================================================	//
always @(posedge clock) begin
	if(reset) begin
		spad_read_addr <= 'd0;
	end
	else begin 
		spad_read_addr <= next_data_read_addr;
	end
end

always @(posedge clock) begin
	if (reset) begin
		spad_write_addr <= 'd0;
	end 
	else if (data_in_shake) begin
		if (write_fin) begin
			spad_write_addr <= 'd0;
		end 
		else begin
			spad_write_addr <= spad_write_addr + 'd1;
		end
	end
end

always @(posedge clock) begin	
	if (reset) begin
		column_num <= 'd0;
	end 
	else if (read_idx_en) begin
		column_num <= read_idx;
	end 
	else if (index_inc) begin
		if (read_fin) begin
			column_num <= 'd0;
		end 
		else begin
			column_num <= column_num + 'd1;
		end
	end
end


// ====================================================	//
// 						 BRAM IP	  					//
// ====================================================	//
wire 			IP_BRAM_write_en	= data_in_shake;
wire			IP_BRAM_read_en		= 'd1;
wire 	[6:0]	IP_BRAM_write_addr	= spad_write_addr;
wire 	[6:0]	IP_BRAM_read_addr	= next_data_read_addr;
wire	[11:0]	IP_BRAM_data_in		= data_in;
wire	[11:0]	IP_BRAM_data_out;

assign data_out	= IP_BRAM_data_out;
	
Weight_DATA_Spad_BRAM Weight_DATA_Spad_BRAM_inst (
    .clk			(clock					),
	.reset			(reset					),
	.write_en       (IP_BRAM_write_en       ),
	.read_en        (IP_BRAM_read_en        ),
	.write_addr     (IP_BRAM_write_addr     ),
	.read_addr      (IP_BRAM_read_addr      ),
	.data_in        (IP_BRAM_data_in        ),
	.data_out       (IP_BRAM_data_out       )
);

endmodule


module Weight_DATA_Spad_BRAM (
    input 			clk,
	input			reset,
	input 			write_en,
	input			read_en,
	
	input 	[6:0]	write_addr,
	input 	[6:0]	read_addr,
	
	input	[11:0]	data_in,
	
	output	[11:0]	data_out
);

wire		wr;
wire [6:0] 	addra;
wire [11:0] dina;
wire [11:0] douta;

IP_Weight_DATA_Spad_BRAM u0 (   	
  .clka		(clk	),    	
  .rsta		(reset	),
  .wea		(wr		),      	
  .addra	(addra	),  	
  .dina		(dina	),    	
  .douta	(douta	)  	
);

// need 100 cycles to clear spad data
reg	[6:0]	clear_count;
reg 		clear_flag;
always @(posedge clk) begin
	if (reset) begin
		clear_flag <= 'd1; 
	end
	else if(clear_count == 'd99) begin
		clear_flag <= 'd0; 
	end
end

always @(posedge clk) begin
	if (reset) begin
		clear_count <= 'd0; 
	end
	else if(clear_flag) begin
		clear_count <= (clear_count == 'd99) ? 'd0 : (clear_count + 'd1); 
	end
end

assign wr		= write_en | clear_flag;
assign addra 	= wr ? (clear_flag ? clear_count : write_addr) : read_addr;
assign dina 	= clear_flag ? 'd0 : data_in;

assign data_out = douta;


endmodule

// ===== repo/FPGA_design/src/PE_Cluster/PE/SPad/Psum_Spad.v =====
// ====================================================================================================== //
// This module is the psum spad.
// psum spad is used to store the psum data from iact * weight and accumulate with previous psum data.
// 
// psum spad depth is from the depth of th multiplication of former matrix and later matrix.
// In this design the former matrix shape is (8, 25), later matrix shape is (25, 4). Hence, the psum shape is (8, 4) = 32
// The shape of former matrix and later matrix can be scale for custom design.
// 
// The bitwidth of iact data is 8, The bitwidth of weight data is 8, The bitwidth of product from iact and weight is 16, 
// I set the maximum times of accumulation is 6, which is 2 PE cluster requirment
// (one PE cluster contains 3 rows of PE, hence it will be accumulated 6 timees) 
// 
// For FPGA implementation, psum spad uses BRAM to store data.
// ====================================================================================================== //


module Psum_Spad (
	input         			clock,
	input         			reset,
	// data signals
	output        			psum_in_ready,
	input         			psum_in_valid,
	input 	signed 	[20:0] 	psum_in,
	input         			psum_out_ready,
	output        			psum_out_vaild,
	output 	signed 	[20:0] 	psum_out,
	// control signals
	input  			[4:0]  	read_idx,
	input  			[4:0]  	write_idx,
	input					psum_spad_clear	
	/*  This signal is used to clear psum spad data, because when PE accumulates data, 
		it will read psum data first,
		then accemulate the psum spad data with the product from iact and weight 
	*/
);

// ================================================	//
// 					 Parameters  					//
// ================================================	//
localparam SPAD_DEPTH = 32; // (8, 25) * (25, 4) = (8, 4), Matrix shape
localparam SPAD_WIDTH = 21;


// ================================================	//
// 					 	Wires  						//
// ================================================	//
wire  data_in_shake = psum_in_ready & psum_in_valid;


// ================================================	//
// 					 Combination  					//
// ================================================	//
assign psum_in_ready 	= ~psum_out_ready; 
assign psum_out_vaild 	= ~psum_in_valid; 



// ====================================================	//
// 						 BRAM IP	  					//
// ====================================================	//
wire					IP_BRAM_reset		= reset | psum_spad_clear;
wire 					IP_BRAM_write_en	= data_in_shake;
wire 			[4:0]	IP_BRAM_write_addr	= write_idx;
wire 			[4:0]	IP_BRAM_read_addr	= read_idx;
wire	signed	[20:0]	IP_BRAM_data_in		= psum_in;
wire	signed	[20:0]	IP_BRAM_data_out;

assign psum_out	= IP_BRAM_data_out;
	
Psum_DATA_Spad_BRAM Psum_DATA_Spad_BRAM_inst (
    .clk			(clock					),
	.reset			(IP_BRAM_reset			),
	.write_en       (IP_BRAM_write_en       ),
	.write_addr     (IP_BRAM_write_addr     ),
	.read_addr      (IP_BRAM_read_addr      ),
	.data_in        (IP_BRAM_data_in        ),
	.data_out       (IP_BRAM_data_out       )
);

endmodule


module Psum_DATA_Spad_BRAM (
    input 					clk,
	input					reset,
	input 					write_en,
			
	input 			[4:0]	write_addr,
	input 			[4:0]	read_addr,
	
	input	signed	[20:0]	data_in,
	
	output	signed	[20:0]	data_out
);

wire					wr;
wire 			[4:0] 	addra;
wire	signed	[20:0] 	dina;
wire 			[4:0] 	addrb;
wire	signed	[20:0] 	doutb;

IP_Psum_DATA_Spad_BRAM u0 (   	
  .clka		(clk	),  
  .wea		(wr		),     	
  .addra	(addra	),  	
  .dina		(dina	),  
  
  .clkb		(clk	),  
  .rstb		(reset	),     
  .addrb	(addrb	),  	  
  .doutb	(doutb	)  	
);

// need 32 cycles to clear spad data
reg			[4:0] 	clear_count;
reg 				clear_flag;
reg					wr_reg;
reg	signed	[20:0] 	data_out_reg;

always @(posedge clk) begin
	if (reset) begin
		clear_flag <= 'd1; 
	end
	else if(clear_count == 'd31) begin
		clear_flag <= 'd0; 
	end
end

always @(posedge clk) begin
	if (reset) begin
		clear_count <= 'd0; 
	end
	else if(clear_flag) begin
		clear_count <= clear_count + 'd1; 
	end
end

always @(posedge clk) begin
	if (reset) begin
		wr_reg <= 'd0; 
	end
	else begin
		wr_reg <= wr; 
	end
end

always @(posedge clk) begin
	if (reset) begin
		data_out_reg <= 'd0; 
	end
	else begin
		data_out_reg <= doutb; 
	end
end

assign addra 	= clear_flag ? clear_count : write_addr;
assign addrb 	= read_addr;
assign dina 	= clear_flag ? 'd0 : data_in;
assign wr		= write_en | clear_flag;

assign data_out = wr_reg ? data_out_reg : doutb;


endmodule


// ===== repo/FPGA_design/src/Pooling/Max_pooling.v =====
// ====================================================================================================== //
// This module is Max_pooling.
// This module only contains a buffer for 2x2 data and find_max logic.
// In this design, the pooling function only supports 2x2 max pooling.
// 
// TODO : extend this pooling module supported different poolong types, 
// such as average pooling, mini pooling, 4x4, 8x8, etc...
// 
// for different types of pooling it only need to revise 
// the counter and buffer depth and the number of stage of find max logic.
// ====================================================================================================== //


module Max_pooling #(
	parameter stride = 2
	)
(	
	input						clock,
	input						reset,
	input						enable,
	
	input		signed	[7:0]	data_in,
	input						data_in_valid,
	
	output	 	signed	[7:0]	data_out,
	output						data_out_valid
);


// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
localparam	BUFFER_DEPTH = stride*stride;


// ====================================================================	//
// 						 		Registers  								//
// ====================================================================	//
reg	signed	[7:0] 	find_max_buffer [0:BUFFER_DEPTH-1];
reg			[1:0] 	addr;
reg	 				buffer_full_reg;


// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
// find max 2-stage comparator
wire signed	[7:0] 	max_valule_0_1	= (find_max_buffer[0] > find_max_buffer[1]) ? find_max_buffer[0] : find_max_buffer[1];
wire signed	[7:0] 	max_valule_2_3	= (find_max_buffer[2] > find_max_buffer[3]) ? find_max_buffer[2] : find_max_buffer[3];
wire signed	[7:0] 	max_value		= (max_valule_0_1 > max_valule_2_3) ? max_valule_0_1 : max_valule_2_3;

wire 				buffer_full 	= addr == 'd3;


// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
assign	data_out		= buffer_full_reg ? max_value : 'd0;
assign	data_out_valid 	= buffer_full_reg;


// ====================================================================	//
// 						 		Sequential  							//
// ====================================================================	//
integer i;
always@(posedge clock) begin
	if(reset) begin
		for(i=0; i<BUFFER_DEPTH; i=i+1) begin
			find_max_buffer[i] <= 'sd0;
		end
	end
	else if(enable & data_in_valid) begin
		find_max_buffer[addr] <= data_in;
	end
end


always@(posedge clock) begin
	if(reset) begin
		addr <= 'd0;
	end
	else if(enable) begin
		addr <= addr + 'd1;
	end
end

always@(posedge clock) begin
	if(reset) begin
		buffer_full_reg <= 'd0;
	end
	else begin
		buffer_full_reg <= buffer_full;
	end
end


endmodule

// ===== repo/FPGA_design/src/Quantizer/Psum_Requantizer.v =====
// ====================================================================================================== //
// This module is Psum_Requantizer.
// The quantization scheme is a simple shifter.
//
// Since psum will be accumulated with several times, in this design the maximum accumulated time is 6,
// which means the bitwidth of data will be extended to 21-bit. (8+8+(6-1))
// it must be requantized back to 8-bit precision.
//
// For normal case, the shifter should shift 13-bit, but this chip is for SCNN, in ordeer to avoid the data 
// vanishing by requantization, this module only shift 2-bit to reserve the information of data.
// ====================================================================================================== //

module Psum_Requantizer (
	input	signed	[20:0]	data_in,
	input					data_in_valid,
	output	signed	[7:0]	data_out,
	output					data_out_valid
);

assign data_out = data_in [17:10];
assign data_out_valid = data_in_valid;


endmodule

// ===== repo/FPGA_design/src/Router_Cluster/Iact_Router.v =====
// ====================================================================================================== //
// This module is iact router.
// iact router module is pure circuit switching (MUX).
// 9 iact SRAM connect to 9 PE in PE clusteer (one-to-one) through iact routers.
// There are 4 ports(north, south, horiz, PE & GLB) in this module.
// This module contains 3 types of internal signals, internal_data, internal_data_valid, internal_data_ready.
// There 2 control signals from upper module, data_in_sel, data_out_sel, which can control the switching mode.
// data_in_sel and data_out_sel with valid and ready protocol, would estabalish 3-way handshake.
// 
// For data signals,  one large MUX deals 4 ports input data  signals and use data_in_sel  to determine internal_data.
// For valid signals, one large MUX deals 4 ports input valid signals and use data_in_sel  to determine internal_valid.
// For ready signals, one large MUX deals 4 ports input ready signals and use data_out_sel to determine internal_ready.
//  
// data  out signals are connected directly to internal_data.
// valid out signals are determine by a MUX with data_out_sel control.
// ready out signals are determine by a MUX with data_in_sel control.
// 
// In iact router, input signals are always sent to PE.
// ====================================================================================================== //


module Iact_Router (
	// source ports
	output 		       GLB_address_in_ready,
	input  		       GLB_address_in_valid,
	input  		[6:0]  GLB_address_in,
	output 		       GLB_data_in_ready,
	input  		       GLB_data_in_valid,
	input  		[11:0] GLB_data_in,
			
	output 		       north_address_in_ready,
	input  		       north_address_in_valid,
	input  		[6:0]  north_address_in,
	output 		       north_data_in_ready,
	input  		       north_data_in_valid,
	input  		[11:0] north_data_in,
			
	output 		       south_address_in_ready,
	input  		       south_address_in_valid,
	input  		[6:0]  south_address_in,
	output 		       south_data_in_ready,
	input  		       south_data_in_valid,
	input  		[11:0] south_data_in,
			
	output 		       horiz_address_in_ready,
	input  		       horiz_address_in_valid,
	input  		[6:0]  horiz_address_in,
	output 		       horiz_data_in_ready,
	input  		       horiz_data_in_valid,
	input  		[11:0] horiz_data_in,
	
	// destination ports
	input         		PE_address_out_ready,
	output 		       	PE_address_out_valid,
	output		[6:0]  	PE_address_out,
	input         		PE_data_out_ready,
	output        		PE_data_out_valid,
	output 	 	[11:0] 	PE_data_out,
	
	input				north_address_out_ready,
	output 	reg        	north_address_out_valid,
	output 	 	[6:0]  	north_address_out,
	input				north_data_out_ready,
	output 	reg        	north_data_out_valid,
	output 	 	[11:0] 	north_data_out,
	
	input         		south_address_out_ready,
	output 	reg        	south_address_out_valid,
	output 	 	[6:0]  	south_address_out,
	input         		south_data_out_ready,
	output 	reg        	south_data_out_valid,
	output 	 	[11:0] 	south_data_out,
	
	input         		horiz_address_out_ready,
	output 	reg        	horiz_address_out_valid,
	output 	 	[6:0]  	horiz_address_out,
	input         		horiz_data_out_ready,
	output	reg	       	horiz_data_out_valid,
	output 	 	[11:0]	horiz_data_out,
	
	// control
	input  		[1:0]  	data_in_sel,
	input  		[1:0]  	data_out_sel
);


// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
// data out direction
localparam UNICAST 		= 2'b00;
localparam HOR_CAST		= 2'b01;
localparam VER_CAST		= 2'b10;
localparam BROADCAST 	= 2'b11;

// data in direction
localparam GLB   = 2'b00;
localparam NORTH = 2'b01;
localparam SOUTH = 2'b10;
localparam HORIZ = 2'b11;


// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
reg  		internal_address_ready;
reg  		internal_data_ready;
reg  		internal_address_valid;
reg  		internal_data_valid;
reg [6:0] 	internal_address;
reg [11:0]	internal_data;


// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
// output in_ready signals
assign GLB_address_in_ready 	= (data_in_sel == GLB) 	 & internal_address_ready;
assign GLB_data_in_ready 		= (data_in_sel == GLB) 	 & internal_data_ready; 
														 
assign north_address_in_ready 	= (data_in_sel == NORTH) & internal_address_ready;
assign north_data_in_ready 		= (data_in_sel == NORTH) & internal_data_ready;
														 
assign south_address_in_ready 	= (data_in_sel == SOUTH) & internal_address_ready;
assign south_data_in_ready 		= (data_in_sel == SOUTH) & internal_data_ready;
														 
assign horiz_address_in_ready	= (data_in_sel == HORIZ) & internal_address_ready;
assign horiz_data_in_ready 		= (data_in_sel == HORIZ) & internal_data_ready;

// data and address are always sent to PE
assign PE_address_out_valid = internal_address_valid;
assign PE_data_out_valid	= internal_data_valid;

// internal data and address are connected to all ports
assign PE_address_out		= internal_address;
assign north_address_out 	= internal_address;
assign south_address_out 	= internal_address;
assign horiz_address_out 	= internal_address;
assign PE_data_out			= internal_data;
assign north_data_out 		= internal_data;
assign south_data_out 		= internal_data;
assign horiz_data_out 		= internal_data;

// use vvalid signal to determine routing mode
always@(*) begin
	case(data_out_sel)
		UNICAST : begin
			north_address_out_valid = 1'b0;
			south_address_out_valid	= 1'b0;
			horiz_address_out_valid = 1'b0;
			north_data_out_valid 	= 1'b0;
			south_data_out_valid 	= 1'b0;
			horiz_data_out_valid 	= 1'b0;
		end	
		HOR_CAST : begin
			north_address_out_valid = 1'b0;
			south_address_out_valid = 1'b0;
			horiz_address_out_valid = internal_address_valid;
			north_data_out_valid 	= 1'b0;
			south_data_out_valid 	= 1'b0;
			horiz_data_out_valid 	= internal_data_valid;
		end	
		VER_CAST : begin
			north_address_out_valid = internal_address_valid; 
			south_address_out_valid = internal_address_valid; 
			horiz_address_out_valid = 1'b0;
			north_data_out_valid 	= internal_data_valid; 
			south_data_out_valid 	= internal_data_valid; 
			horiz_data_out_valid 	= 1'b0;
		end	
		BROADCAST : begin
			north_address_out_valid = internal_address_valid; 
			south_address_out_valid = internal_address_valid; 
			horiz_address_out_valid = internal_address_valid;
			north_data_out_valid 	= internal_data_valid; 
			south_data_out_valid 	= internal_data_valid; 
			horiz_data_out_valid 	= internal_data_valid;
		end	
		default : begin
			north_address_out_valid = 'd0;
			south_address_out_valid = 'd0;
			horiz_address_out_valid = 'd0;
			north_data_out_valid 	= 'd0;
			south_data_out_valid 	= 'd0;
			horiz_data_out_valid 	= 'd0;
		end	                        
	endcase                         
end


// internal signals
always@(*) begin
	case(data_out_sel)
		UNICAST 		: internal_address_ready = PE_address_out_ready;
		HOR_CAST   : internal_address_ready = PE_address_out_ready & horiz_address_out_ready;
		VER_CAST	: internal_address_ready = PE_address_out_ready & south_address_out_ready;
		BROADCAST 	   	: internal_address_ready = PE_address_out_ready & north_address_out_ready & south_address_out_ready & horiz_address_out_ready;
		default 		: internal_address_ready = 1'b1;
	endcase
end

always@(*) begin
	case(data_out_sel)
		UNICAST 		: internal_data_ready = PE_data_out_ready;
		HOR_CAST   : internal_data_ready = PE_data_out_ready & horiz_data_out_ready;
		VER_CAST	: internal_data_ready = PE_data_out_ready & south_data_out_ready; 
		BROADCAST 	   	: internal_data_ready = PE_data_out_ready & north_data_out_ready & south_data_out_ready & horiz_data_out_ready; 
		default 		: internal_data_ready = 1'b1;
	endcase
end

always@(*) begin
	case(data_in_sel)
		GLB     : internal_address_valid = GLB_address_in_valid;
		NORTH   : internal_address_valid = north_address_in_valid;
		SOUTH   : internal_address_valid = south_address_in_valid;
		HORIZ   : internal_address_valid = horiz_address_in_valid;
		default : internal_address_valid = 1'b0;
	endcase
end

always@(*) begin
	case(data_in_sel)
		GLB     : internal_data_valid = GLB_data_in_valid;
		NORTH   : internal_data_valid = north_data_in_valid;
		SOUTH   : internal_data_valid = south_data_in_valid;
		HORIZ   : internal_data_valid = horiz_data_in_valid;
		default : internal_data_valid = 1'b0;
	endcase
end

always@(*) begin
	case(data_in_sel)
		GLB     : internal_address = GLB_address_in;
		NORTH   : internal_address = north_address_in;
		SOUTH   : internal_address = south_address_in;
		HORIZ   : internal_address = horiz_address_in;
		default : internal_address = 'd0;
	endcase
end

always@(*) begin
	case(data_in_sel)
		GLB     : internal_data = GLB_data_in;
		NORTH   : internal_data = north_data_in;
		SOUTH   : internal_data = south_data_in;
		HORIZ   : internal_data = horiz_data_in;
		default : internal_data = 'd0;
	endcase
end


endmodule
// ===== repo/FPGA_design/src/Router_Cluster/Psum_Router.v =====
// ====================================================================================================== //
// This module is psum router.
// psum router module is pure circuit switching (MUX).
// 3 psum ports in GLB connect to 3 PE in PE clusteer (one-to-one solumn) through psum routers.
// There are 3 ports(north, south, PE & GLB) in this module.
// This module contains 3 types of internal signals, internal_data, internal_data_valid, internal_data_ready.
// There 2 control signals from upper module, data_in_sel, data_out_sel, which can control the switching mode.
// data_in_sel and data_out_sel with valid and ready protocol, would estabalish 3-way handshake.
// 
// For data signals,  one MUX deals 2 ports input data  signals and use data_in_sel  to determine internal_data.
// For valid signals, one MUX deals 2 ports input valid signals and use data_in_sel  to determine internal_valid.
// For ready signals, one MUX deals 2 ports input ready signals and use data_out_sel to determine internal_ready.
//  
// data  out signals are connected directly to internal_data.
// valid out signals are determine by a MUX with data_out_sel control.
// ready out signals are determine by a MUX with data_in_sel control.
// 
// In psum router, the input signals of GLB are always sent to PE.
// ====================================================================================================== //


module Psum_Router (
	// source ports
	output        			PE_in_ready,
	input         			PE_in_valid,
	input	signed 	[20:0] 	PE_in,
	
	output        			GLB_in_ready,
	input         			GLB_in_valid,
	input 	signed	[20:0] 	GLB_in,
	
	output        			north_in_ready,
	input         			north_in_valid,
	input 	signed 	[20:0] 	north_in,
	
	// destination ports
	input         			PE_out_ready,
	output        			PE_out_valid,
	output 	signed 	[20:0]	PE_out,
	
	input         			GLB_out_ready,
	output        			GLB_out_valid,
	output 	signed 	[20:0]	GLB_out,
	
	input         			south_out_ready,
	output        			south_out_valid,
	output 	signed	[20:0]	south_out,
	
	// control
	input         			data_in_sel,
	input         			data_out_sel
);


// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
// data in direction
localparam FROM_NOR = 1'b0;
localparam FROM_GLB = 1'b1;

// data out direction
localparam TO_SOU 	= 1'b0;
localparam TO_PE  	= 1'b1;


// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
// internal wire
wire internal_ready = (data_out_sel == TO_PE) 	? PE_out_ready 	: south_out_ready;
wire internal_valid = (data_in_sel == FROM_GLB) ? GLB_in_valid 	: north_in_valid;
wire internal_data 	= (data_in_sel == FROM_GLB) ? GLB_in 		: north_in;


// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
// PE always sent to GLB
assign PE_in_ready 		= GLB_out_ready;
assign GLB_out_valid 	= PE_in_valid;
assign GLB_out 			= PE_in;

assign GLB_in_ready 	= (data_in_sel == FROM_GLB) & internal_ready;
assign north_in_ready 	= (data_in_sel == FROM_NOR) & internal_ready;

assign PE_out_valid 	= (data_out_sel == TO_PE) 	& internal_valid;
assign PE_out 			= internal_data;

assign south_out_valid 	= (data_out_sel == TO_SOU) 	& internal_valid;
assign south_out 		= internal_data;

endmodule

// ===== repo/FPGA_design/src/Router_Cluster/Router_Cluster.v =====
// ====================================================================================================== //
// This module is router cluster.
// router cluster module inregrates 9 iact routers, 3 weight routers, 3 psum routers.
// This module is one of the main part in this accelerator architecture.
// Its iact   routers are connected to all PEs 			  in PE cluster (one-to-one). 
// Its weight routers are connected to all rows of PEs 	  in PE cluster (one-to-row). 
// Its psum   routers are connected to all columns of PEs in PE cluster (one=to-column). 
//
// router cluster is the core of Hierarchical mesh-NoC, which can provide flexibility to the accelerator.
// This architecture can support all types of data flow topology wiht data_in_sel and data_out_sel control signals.
