// ===== repo/FPGA_design/src/Router_Cluster/Weight_Router.v =====
// ====================================================================================================== //
// This module is weight router.
// weight router module is pure circuit switching (MUX).
// 3 weight ports in GLB connect to 3 PE in PE clusteer (one-to-one row) through weight routers.
// There are 2 ports(horiz, PE & GLB) in this module.
// This module contains 3 types of internal signals, internal_data, internal_data_valid, internal_data_ready.
// There 2 control signals from upper module, data_in_sel, data_out_sel, which can control the switching mode.
// data_in_sel and data_out_sel with valid and ready protocol, would estabalish 3-way handshake.
// 
// For data signals,  one large MUX deals 2 ports input data  signals and use data_in_sel  to determine internal_data.
// For valid signals, one large MUX deals 2 ports input valid signals and use data_in_sel  to determine internal_valid.
// For ready signals, one large MUX deals 2 ports input ready signals and use data_out_sel to determine internal_ready.
//  
// data  out signals are connected directly to internal_data.
// valid out signals are determine by a MUX with data_out_sel control.
// ready out signals are determine by a MUX with data_in_sel control.
// 
// In weight router, input signals are always sent to PE.
// ====================================================================================================== //


module Weight_Router (
	// source ports
	output        GLB_address_in_ready,
	input         GLB_address_in_valid,
	input  [7:0]  GLB_address_in,
	output        GLB_data_in_ready,
	input         GLB_data_in_valid,
	input  [12:0] GLB_data_in,
	
	output        horiz_address_in_ready,
	input         horiz_address_in_valid,
	input  [7:0]  horiz_address_in,
	output        horiz_data_in_ready,
	input         horiz_data_in_valid,
	input  [12:0] horiz_data_in,
	
	// destination ports
	output        PE_address_out_valid,
	output [7:0]  PE_address_out,
	output        PE_data_out_valid,
	output [12:0] PE_data_out,
	
	input         horiz_address_out_ready,
	output        horiz_address_out_valid,
	output [7:0]  horiz_address_out,
	input         horiz_data_out_ready,
	output        horiz_data_out_valid,
	output [12:0] horiz_data_out,
	
	// control signals
	input         data_in_sel,
	input         data_out_sel
);


// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
// data out direction
localparam UNICAST 	= 1'b0;
localparam HOR_CAST = 1'b1;

// data in direction
localparam GLB   	= 1'b0;
localparam HORIZ	= 1'b1;


// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
// internal signals
wire internal_address_ready 	= (data_out_sel == HOR_CAST) 	? horiz_address_out_ready 	: 1'b1; // PE interface is always ready
wire internal_data_ready 		= (data_out_sel == HOR_CAST) 	? horiz_data_out_ready  	: 1'b1;
	
wire internal_address_valid 	= (data_in_sel == HORIZ) 		? horiz_address_in_valid 	: GLB_address_in_valid;
wire internal_data_valid 		= (data_in_sel == HORIZ) 		? horiz_data_in_valid 		: GLB_data_in_valid;

wire [7:0]	internal_address 	= (data_in_sel == HORIZ) 		? horiz_address_in 			: GLB_address_in;
wire [12:0]	internal_data 		= (data_in_sel == HORIZ) 		? horiz_data_in 			: GLB_data_in;

// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
// in ready switching
assign GLB_address_in_ready 	= (data_in_sel == GLB)	 & internal_address_ready;
assign GLB_data_in_ready 		= (data_in_sel == GLB)	 & internal_data_ready;
														 
assign horiz_address_in_ready 	= (data_in_sel == HORIZ) & internal_address_ready;
assign horiz_data_in_ready 		= (data_in_sel == HORIZ) & internal_data_ready;

// data out switching
assign PE_address_out_valid 	= internal_address_valid;
assign PE_address_out 			= internal_address;
					
assign PE_data_out_valid 		= internal_data_valid;
assign PE_data_out 				= internal_data;

assign horiz_address_out_valid 	= (data_out_sel == HOR_CAST) & internal_address_valid;
assign horiz_address_out 		= internal_address;
	
assign horiz_data_out_valid 	= (data_out_sel == HOR_CAST) & internal_data_valid;
assign horiz_data_out 			= internal_data;


endmodule

// ===== repo/FPGA_design/src/TOP/Psum_rearrange.v =====
// ====================================================================================================== //
// This module is psum_rearrange buffer.
// psum_rearrange is only used to store data from psum SRAM bank to rearrange.
// The data in this buffer is ifmap of the next layer.
// ====================================================================================================== //


module psum_rearrange (
	input        				clock,
	input        				reset,	
	
	input  	 					write_en,
	input				[11:0]	write_addr,
	input		signed	[7:0] 	data_in,
	input        				data_in_valid,
	
	input				[11:0] 	read_addr,
	output		signed	[7:0]	data_out
);


// ====================================================================	//
// 						 		Parameters  							//
// ====================================================================	//
localparam BUFFER_DEPTH = 3500;	// 576*6=3456


// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
wire data_in_shake = write_en & data_in_valid;


// ====================================================	//
// 						 BRAM IP	  					//
// ====================================================	//
wire 					IP_BRAM_write_en	= data_in_shake;
wire 			[11:0]	IP_BRAM_write_addr	= write_addr;
wire 			[11:0]	IP_BRAM_read_addr	= read_addr;
wire	signed	[7:0]	IP_BRAM_data_in		= data_in;
wire	signed	[7:0]	IP_BRAM_data_out;

assign data_out	= IP_BRAM_data_out;
	
Psum_Rearrange_BRAM Psum_Rearrange_BRAM_inst (
    .clk			(clock					),
	.reset			(reset					),
	.write_en       (IP_BRAM_write_en       ),
	.write_addr     (IP_BRAM_write_addr     ),
	.read_addr      (IP_BRAM_read_addr      ),
	.data_in        (IP_BRAM_data_in        ),
	.data_out       (IP_BRAM_data_out       )
);

endmodule


module Psum_Rearrange_BRAM (
    input 					clk,
	input					reset,
	input 					write_en,
			
	input 			[11:0]	write_addr,
	input 			[11:0]	read_addr,
	
	input	signed	[7:0]	data_in,
	
	output	signed	[7:0]	data_out
);

wire					wr;
wire 			[11:0] 	addra;
wire	signed	[7:0] 	dina;
wire 			[11:0] 	addrb;
wire	signed	[7:0] 	doutb;

IP_Psum_Rearrange_BRAM u0 (   	
  .clka		(clk	),  
  .wea		(wr		),     	
  .addra	(addra	),  	
  .dina		(dina	),  
  
  .clkb		(clk	),  
  .rstb		(reset	),     
  .addrb	(addrb	),  	  
  .doutb	(doutb	)  	
);


// need 4096 cycles to clear spad data
reg	[11:0] 	clear_count;
reg 		clear_flag;

always @(posedge clk) begin
	if (reset) begin
		clear_flag <= 'd1; 
	end
	else if(clear_count == 'd4095) begin
		clear_flag <= 'd0; 
	end
end

always @(posedge clk) begin
	if (reset) begin
		clear_count <= 'd0; 
	end
	else if(clear_flag) begin
		clear_count <= clear_count + 'd1; 
	end
end


assign addra 	= (clear_flag & ~write_en) ? clear_count : write_addr;
assign addrb 	= read_addr;
assign dina 	= clear_flag ? 'd0 : data_in;
assign wr		= write_en | clear_flag;

assign data_out = doutb;


endmodule

// ===== repo/FPGA_design/src/TOP/Psum_SRAM_out_acc.v =====
module psum_SRAM_out_acc #(
	parameter BATCHES 	= 4,
	parameter CHANNELS 	= 3
	)
(
	input 						clock,
	input 						reset,
	input 						en,
	
	input		signed	[20:0]	data_in,
	input						data_in_valid,
					 
	output	reg signed	[20:0]	data_out,
	output	reg 				data_out_valid
);

/*
	C0~5
	C6~11
	C12~15
*/
localparam BUFFER_DEPTH = BATCHES*CHANNELS;

reg	signed	[20:0] Buffer [0:BUFFER_DEPTH-1];
reg	[3:0] idx;
reg en_reg;
reg en_pulse_reg;
wire en_pulse = en & (~en_reg);

wire data_in_en = en_reg & data_in_valid;

wire signed	[20:0]	data_out_batch_0 = Buffer[0] + Buffer[4] + Buffer[8];
wire signed	[20:0]	data_out_batch_1 = Buffer[1] + Buffer[5] + Buffer[9];
wire signed	[20:0]	data_out_batch_2 = Buffer[2] + Buffer[6] + Buffer[10];
wire signed	[20:0]	data_out_batch_3 = Buffer[3] + Buffer[7] + Buffer[11];
		  
integer i;
always@(posedge clock) begin
	if(reset) begin
		for(i=0; i<BUFFER_DEPTH; i=i+1) begin
			Buffer[i] <= 'd0;
		end
	end
	else if(data_in_en) begin
		Buffer[idx] <= data_in;
	end
end


always@(posedge clock) begin
	if(reset) begin
		idx <= 'd0;
	end
	else if(data_in_en) begin
		idx <= (idx == 'd11) ? 'd0 : (idx + 'd1);
	end
end


always@(posedge clock) begin
	if(reset) begin
		data_out <= 'd0;
	end
	else begin
		case(idx)
			'd9		: data_out <= data_out_batch_0;
			'd10	: data_out <= data_out_batch_1;
			'd11	: data_out <= data_out_batch_2;
			'd0		: data_out <= data_out_batch_3;
			default : data_out <= 'd0;
		endcase
	end
end

always@(posedge clock) begin
	if(reset) begin
		data_out_valid <= 'd0;
	end
	else if((idx == 'd9) | (idx == 'd10) | (idx == 'd11) | (idx == 'd0) & ~en_pulse_reg & en_reg) begin
		data_out_valid <= 'd1;
	end
	else begin
		data_out_valid <= 'd0;
	end
end

always@(posedge clock) begin
	if(reset) begin
		en_reg 			<= 'd0;
		en_pulse_reg 	<= 'd0;
	end
	else begin
		en_reg 			<= en;
		en_pulse_reg 	<= en_pulse;
	end
end



endmodule

// ===== repo/FPGA_design/src/TOP/SCNN_shape_info_compiler.v =====
// ====================================================================================================== //
// 
//
//
//
// 
// ====================================================================================================== //


module SCNN_shape_info_compiler (
	input				clock,
	input				reset,
	
	// NN shape
	input		[9:0]	image_size,
	input		[9:0]	image_channels,
	input		[2:0]	filter_size,
	input		[4:0]	filter_numbers,
	
	input		[2:0]	total_layers,
	
	// TOP signal
	input		[2:0]	layer_count,

	
	output		[5:0]	psum_depth,
	output		[7:0]	psum_acc_times_bound,
	
	// im2col addressing jump values
	output		[9:0]	im2col_ifmap_len,
	output		[9:0]	im2col_read_psum_addr_bound,
	output		[4:0]	im2col_ofmap_size,
	output		[9:0]	im2col_next_vector_jump,
	output		[9:0]	im2col_next_ifmap_row_jump,
	output		[9:0]	im2col_next_weight_row_jump,
	
	// CSC Encoder
	output		[4:0]	CSC_encoder_iact_matrix_height,
	output		[4:0]	CSC_encoder_iact_matrix_width,
	
	output		[4:0]	CSC_encoder_weight_matrix_height,
	output		[4:0]	CSC_encoder_weight_matrix_width,
	
	// GLB psum read
	output 		[1:0] 	fc_GLB_psum_read_channel_bound,
	output 		[2:0] 	fc_GLB_psum_read_batche_bound,
	output		[2:0] 	fc_GLB_psum_read_sel_bound,
	output		[4:0]	fc_psum_rearrange_read_count_bound,
	output		[4:0]	fc_psum_rearrange_read_channel_bound,
	
	output		[5:0]	GLB_iact_en_sel_bound,
	output		[2:0]	GLB_iact_load_batch_bound,
	output		[2:0]	GLB_iact_load_channel_bound,
	output		[2:0]	GLB_iact_load_iter_bound,
	
	output		[2:0]	GLB_weight_load_channel_bound,
	
	output		[2:0]	psum_read_out_channel_bound,
	
	
	
	
);





// ====================================================================	//
// 						 		Registers  								//
// ====================================================================	//
// LUT for model architecture
// layer_0 : conv
// layer_1 : conv
// layer_2 : fc
// layer_3 : fc
// layer_4 : fc
reg [4:0] layer_type_LUT = 5'b00011;	// 1 for conv, 0 for fc




// ====================================================================	//
// 						 		Wires  									//
// ====================================================================	//
wire conv_flag 	= layer_type_LUT[layer_count];
wire fc_flag 	= ~layer_type_LUT[layer_count];

wire [3:0] former_matrix_col 	= filter_numbers > 'd8 ? 'd8 : filter_numbers;	// 0~8
wire [2:0] later_matrix_row 	= 'd4;											//0~4

wire weight_broadcast 			= image_channels < 'd7;							

// usage resource
wire [2:0] use_CG_col = 2;
wire [2:0] use_CG_row = weight_broadcast ? 'd2 : 'd1;
wire [2:0] use_PE_col = 3;
wire [2:0] use_PE_row = weight_broadcast ? 'd1 : 'd3;

wire [9:0] im2col_out_row = (image_size -filter_size + 'd1) * (image_size -filter_size + 'd1);
// ====================================================================	//
// 						 		Combination  							//
// ====================================================================	//
assign psum_depth 			= conv_flag ? (former_matrix_col * later_matrix_row) : later_matrix_row;

assign psum_acc_times_bound	= (im2col_out_row/later_matrix_row) / (use_CG_col*use_CG_row*use_PE_col);


wire psum_acc_done = (layer0_flag & psum_acc_times == 'd12) 	|
                     (layer1_flag & psum_acc_times == 'd6) 		|
                     (layer2_flag & psum_acc_times == 'd15) 	|
                     (layer3_flag & psum_acc_times == 'd4)		|
                     (layer4_flag & psum_acc_times == 'd1);


// ====================================================================	//
// 						 		Sequential  							//
// ====================================================================	//
always@(posedge clock) begin
	if(reset) begin
		
	end
	else if (1'b0) begin
		
	end
end


endmodule

