		GLB_weight_load_channel <= (GLB_weight_load_channel == 'd5) ? 'd0 : (GLB_weight_load_channel + 'd1);
	end
	else if(((weight_addr_end | weight_data_end) & layer1_flag) | (csc_addr_end  & layer4_flag)) begin	// 16 = 6*2 + 4
